module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"사무엘의 출생","verses":{"krv":[{"n":1,"t":"에브라임 산지 라마다임소빔에 에브라임 사람 엘가나라 하는 자가 있으니 그는 여로함의 아들이요 엘리후의 손자요 도후의 증손이요 숩의 현손이더라"},{"n":2,"t":"그에게 두 아내가 있으니 하나의 이름은 한나요 하나의 이름은 브닌나라 브닌나는 자식이 있고 한나는 무자하더라"},{"n":3,"t":"이 사람이 매년에 자기 성읍에서 나와서 실로에 올라가서 만군의 여호와께 경배하며 제사를 드렸는데 엘리의 두 아들 홉니와 비느하스가 여호와의 제사장으로 거기 있었더라"},{"n":4,"t":"엘가나가 제사를 드리는 날에는 제물의 분깃을 그 아내 브닌나와 그 모든 자녀에게 주고"},{"n":5,"t":"한나에게는 갑절을 주니 이는 그를 사랑함이라 그러나 여호와께서 그로 성태치 못하게 하시니"},{"n":6,"t":"여호와께서 그로 성태치 못하게 하시므로 그 대적 브닌나가 그를 심히 격동하여 번민케 하더라"},{"n":7,"t":"매년에 한나가 여호와의 집에 올라갈 때마다 남편이 그같이 하매 브닌나가 그를 격동시키므로 그가 울고 먹지 아니하니"},{"n":8,"t":"그 남편 엘가나가 그에게 이르되 한나여 어찌하여 울며 어찌하여 먹지 아니하며 어찌하여 그대의 마음이 슬프뇨 내가 그대에게 열 아들보다 낫지 아니하뇨"},{"n":9,"t":"그들이 실로에서 먹고 마신 후에 한나가 일어나니 때에 제사장 엘리는 여호와의 전 문설주 곁 그 의자에 앉았더라"},{"n":10,"t":"한나가 마음이 괴로워서 여호와께 기도하고 통곡하며"},{"n":11,"t":"서원하여 가로되 만군의 여호와여 만일 주의 여종의 고통을 돌아보시고 나를 생각하시고 주의 여종을 잊지 아니하사 아들을 주시면 내가 그의 평생에 그를 여호와께 드리고 삭도를 그 머리에 대지 아니하겠나이다"},{"n":12,"t":"그가 여호와 앞에 오래 기도하는 동안에 엘리가 그의 입을 주목한즉"},{"n":13,"t":"한나가 속으로 말하매 입술만 동하고 음성은 들리지 아니하므로 엘리는 그가 취한 줄로 생각한지라"},{"n":14,"t":"엘리가 그에게 이르되 네가 언제까지 취하여 있겠느냐 포도주를 끊으라"},{"n":15,"t":"한나가 대답하여 가로되 나의 주여 그렇지 아니하니이다 나는 마음이 슬픈 여자라 포도주나 독주를 마신 것이 아니요 여호와 앞에 나의 심정을 통한 것뿐이오니"},{"n":16,"t":"당신의 여종을 악한 여자로 여기지 마옵소서 내가 지금까지 말한 것은 나의 원통함과 격동됨이 많음을 인함이니이다"},{"n":17,"t":"엘리가 대답하여 가로되 평안히 가라 이스라엘의 하나님이 너의 기도하여 구한 것을 허락하시기를 원하노라"},{"n":18,"t":"가로되 당신의 여종이 당신께 은혜 입기를 원하나이다 하고 가서 먹고 얼굴에 다시는 수색이 없으니라"},{"n":19,"t":"그들이 아침에 일찍이 일어나 여호와 앞에 경배하고 돌아가서 라마의 자기 집에 이르니라 엘가나가 그 아내 한나와 동침하매 여호와께서 그를 생각하신지라"},{"n":20,"t":"한나가 잉태하고 때가 이르매 아들을 낳아 사무엘이라 이름하였으니 이는 내가 여호와께 그를 구하였다 함이더라"},{"n":21,"t":"그 사람 엘가나와 그 온 집이 여호와께 매년제와 그 서원제를 드리러 올라갈 때에"},{"n":22,"t":"오직 한나는 올라가지 아니하고 그 남편에게 이르되 아이를 젖 떼거든 내가 그를 데리고 가서 여호와 앞에 뵈게 하고 거기 영영히 있게 하리이다"},{"n":23,"t":"그 남편 엘가나가 그에게 이르되 그대의 소견에 선한 대로 하여 그를 젖 떼기까지 기다리라 오직 여호와께서 그 말씀대로 이루시기를 원하노라 이에 그 여자가 그 아들을 양육하며 그 젖 떼기까지 기다리다가"},{"n":24,"t":"젖을 뗀 후에 그를 데리고 올라갈새 수소 셋과 가루 한 에바와 포도주 한 가죽부대를 가지고 실로 여호와의 집에 나아갔는데 아이가 어리더라"},{"n":25,"t":"그들이 수소를 잡고 아이를 데리고 엘리에게 가서"},{"n":26,"t":"한나가 가로되 나의 주여 당신의 사심으로 맹세하나이다 나는 여기서 나의 주 당신 곁에 서서 여호와께 기도하던 여자라"},{"n":27,"t":"이 아이를 위하여 내가 기도하였더니 여호와께서 나의 구하여 기도한 바를 허락하신지라"},{"n":28,"t":"그러므로 나도 그를 여호와께 드리되 그의 평생을 여호와께 드리나이다 하고 그 아이는 거기서 여호와께 경배하니라"}],"kids":[]}},{"chapter":2,"title":"한나의 기도와 엘리의 아들들","verses":{"krv":[{"n":1,"t":"한나가 기도하여 가로되 내 마음이 여호와를 인하여 즐거워하며 내 뿔이 여호와를 인하여 높아졌으며 내 입이 내 원수들을 향하여 크게 열렸으니 이는 내가 주의 구원을 인하여 기뻐함이니이다"},{"n":2,"t":"여호와와 같이 거룩하신 이가 없으시니 이는 주 밖에 다른 이가 없고 우리 하나님 같은 반석도 없으심이니이다"},{"n":3,"t":"심히 교만한 말을 다시 하지 말 것이며 오만한 말을 너희 입에서 내지 말지어다 여호와는 지식의 하나님이시라 행동을 달아보시느니라"},{"n":4,"t":"용사의 활은 꺾이고 넘어진 자는 힘으로 띠를 띠도다"},{"n":5,"t":"유족하던 자들은 양식을 위하여 품을 팔고 주리던 자들은 다시 주리지 않도다 전에 잉태치 못하던 자는 일곱을 낳았고 많은 자녀를 둔 자는 쇠약하도다"},{"n":6,"t":"여호와는 죽이기도 하시고 살리기도 하시며 음부에 내리게도 하시고 올리기도 하시는도다"},{"n":7,"t":"여호와는 가난하게도 하시고 부하게도 하시며 낮추기도 하시고 높이기도 하시는도다"},{"n":8,"t":"가난한 자를 진토에서 일으키시며 빈핍한 자를 거름더미에서 드사 귀족들과 함께 앉게 하시며 영광의 위를 차지하게 하시는도다 땅의 기둥들은 여호와의 것이라 여호와께서 세계를 그 위에 세우셨도다"},{"n":9,"t":"그가 그 거룩한 자들의 발을 지키실 것이요 악인으로 흑암 중에서 잠잠케 하시리니 힘으로는 이길 사람이 없음이로다"},{"n":10,"t":"여호와를 대적하는 자는 산산이 깨어질 것이라 하늘 우뢰로 그들을 치시리로다 여호와께서 땅 끝까지 심판을 베푸시고 자기 왕에게 힘을 주시며 자기의 기름부음을 받은 자의 뿔을 높이시리로다 하니라"},{"n":11,"t":"엘가나는 라마의 자기 집으로 돌아가고 그 아이는 제사장 엘리 앞에서 여호와를 섬기니라"},{"n":12,"t":"엘리의 아들들은 불량자라 여호와를 알지 아니하더라"},{"n":13,"t":"그 제사장들이 백성에게 행하는 습관은 이러하니 곧 아무 사람이 제사를 드리고 그 고기를 삶을 때에 제사장의 사환이 손에 세살 갈고리를 가지고 와서"},{"n":14,"t":"그것으로 남비에나 솥에나 큰 솥에나 가마에 찔러 넣어서 갈고리에 걸려 나오는 것은 제사장이 자기 것으로 취하되 실로에서 무릇 그곳에 온 이스라엘 사람에게 이같이 할 뿐 아니라"},{"n":15,"t":"기름을 태우기 전에도 제사장의 사환이 와서 제사 드리는 사람에게 이르기를 제사장에게 구워 드릴 고기를 내라 그가 네게 삶은 고기를 원치 아니하고 날것을 원하신다 하다가"},{"n":16,"t":"그 사람이 이르기를 반드시 먼저 기름을 태운 후에 네 마음에 원하는 대로 취하라 하면 그가 말하기를 아니라 지금 내게 내라 그렇지 아니하면 내가 억지로 빼앗으리라 하였으니"},{"n":17,"t":"이 소년들의 죄가 여호와 앞에 심히 큼은 그들이 여호와의 제사를 멸시함이었더라"},{"n":18,"t":"사무엘이 어렸을 때에 세마포 에봇을 입고 여호와 앞에 섬겼더라"},{"n":19,"t":"그 어미가 매년제를 드리러 그 남편과 함께 올라갈 때마다 작은 겉옷을 지어다가 그에게 주었더니"},{"n":20,"t":"엘리가 엘가나와 그 아내에게 축복하여 가로되 여호와께서 이 여인으로 말미암아 네게 후사를 주사 이가 여호와께 간구하여 얻어드린 아들을 대신하게 하시기를 원하노라 하였더니 그들이 그 집으로 돌아가매"},{"n":21,"t":"여호와께서 한나를 권고하사 그로 잉태하여 세 아들과 두 딸을 낳게 하셨고 아이 사무엘은 여호와 앞에서 자라니라"},{"n":22,"t":"엘리가 매우 늙었더니 그 아들들이 온 이스라엘에게 행한 모든 일과 회막문에서 수종드는 여인과 동침하였음을 듣고"},{"n":23,"t":"그들에게 이르되 너희가 어찌하여 이런 일을 하느냐 내가 너희의 악행을 이 모든 백성에게서 듣노라"},{"n":24,"t":"내 아들아 그리 말라 내게 들리는 소문이 좋지 아니하니라 너희가 여호와의 백성으로 범과케 하는도다"},{"n":25,"t":"사람이 사람에게 범죄하면 하나님이 판결하시려니와 사람이 여호와께 범죄하면 누가 위하여 간구하겠느냐 하되 그들이 그 아비의 말을 듣지 아니하였으니 이는 여호와께서 그들을 죽이기로 뜻하셨음이었더라"},{"n":26,"t":"아이 사무엘이 점점 자라매 여호와와 사람들에게 은총을 더욱 받더라"},{"n":27,"t":"하나님의 사람이 엘리에게 와서 그에게 이르되 여호와의 말씀에 너희 조상의 집이 애굽에서 바로의 집에 속하였을 때에 내가 그들에게 나타나지 아니하였느냐"},{"n":28,"t":"이스라엘 모든 지파 중에서 내가 그를 택하여 나의 제사장을 삼아 그로 내 단에 올라 분향하며 내 앞에서 에봇을 입게 하지 아니하였느냐 이스라엘 자손의 드리는 모든 화제를 내가 네 조상의 집에 주지 아니하였느냐"},{"n":29,"t":"너희는 어찌하여 내가 나의 처소에서 명한 나의 제물과 예물을 밟으며 네 아들들을 나보다 더 중히 여겨 내 백성 이스라엘의 드리는 가장 좋은 것으로 스스로 살지게 하느냐"},{"n":30,"t":"그러므로 이스라엘의 하나님 나 여호와가 말하노라 내가 전에 네 집과 네 조상의 집이 내 앞에 영영히 행하리라 하였으나 이제 나 여호와가 말하노니 결단코 그렇게 아니하리라 나를 존중히 여기는 자를 내가 존중히 여기고 나를 멸시하는 자를 내가 경멸히 여기리라"},{"n":31,"t":"보라 내가 네 팔과 네 조상의 집 팔을 끊어 네 집에 노인이 하나도 없게 하는 날이 이를지라"},{"n":32,"t":"이스라엘에게 모든 복을 베푸는 중에 너는 내 처소의 환난을 볼 것이요 네 집에 영영토록 노인이 없을 것이며"},{"n":33,"t":"내 단에서 내가 끊어 버리지 아니할 너의 사람이 네 눈을 쇠잔케 하고 네 마음을 슬프게 할 것이요 네 집에 생산하는 모든 자가 젊어서 죽으리라"},{"n":34,"t":"네 두 아들 홉니와 비느하스가 한 날에 죽으리니 그 둘의 당할 그 일이 네게 표징이 되리라"},{"n":35,"t":"내가 나를 위하여 충실한 제사장을 일으키리니 그 사람은 내 마음, 내 뜻대로 행할 것이라 내가 그를 위하여 견고한 집을 세우리니 그가 나의 기름부음을 받은 자 앞에서 영구히 행하리라"},{"n":36,"t":"네 집에 남은 사람이 각기 와서 은 한 조각과 떡 한 덩이를 위하여 그에게 엎드려 가로되 청하노니 내게 한 제사장의 직분을 맡겨 나로 떡 조각을 먹게 하소서 하리라 하셨다 하니라"}],"kids":[]}},{"chapter":3,"title":"사무엘을 부르심","verses":{"krv":[{"n":1,"t":"아이 사무엘이 엘리 앞에서 여호와를 섬길 때에는 여호와의 말씀이 희귀하여 이상이 흔히 보이지 않았더라"},{"n":2,"t":"엘리의 눈이 점점 어두워 가서 잘 보지 못하는 그 때에 그가 자기 처소에 누웠고"},{"n":3,"t":"하나님의 등불은 아직 꺼지지 아니하였으며 사무엘은 하나님의 궤 있는 여호와의 전 안에 누웠더니"},{"n":4,"t":"여호와께서 사무엘을 부르시는지라 그가 대답하되 내가 여기 있나이다 하고"},{"n":5,"t":"엘리에게로 달려가서 가로되 당신이 나를 부르셨기로 내가 여기 있나이다 가로되 나는 부르지 아니하였으니 다시 누우라 그가 가서 누웠더니"},{"n":6,"t":"여호와께서 다시 사무엘을 부르시는지라 사무엘이 일어나서 엘리에게로 가서 가로되 당신이 나를 부르셨기로 내가 여기 있나이다 대답하되 내 아들아 내가 부르지 아니하였으니 다시 누우라 하니라"},{"n":7,"t":"사무엘이 아직 여호와를 알지 못하고 여호와의 말씀도 아직 그에게 나타나지 아니한 때라"},{"n":8,"t":"여호와께서 세번째 사무엘을 부르시는지라 그가 일어나서 엘리에게로 가서 가로되 당신이 나를 부르셨기로 내가 여기 있나이다 엘리가 여호와께서 이 아이를 부르신 줄을 깨닫고"},{"n":9,"t":"이에 사무엘에게 이르되 가서 누웠다가 그가 너를 부르시거든 네가 말하기를 여호와여 말씀하옵소서 주의 종이 듣겠나이다 하라 이에 사무엘이 가서 자기 처소에 누우니라"},{"n":10,"t":"여호와께서 임하여 서서 전과 같이 사무엘아 사무엘아 부르시는지라 사무엘이 가로되 말씀하옵소서 주의 종이 듣겠나이다"},{"n":11,"t":"여호와께서 사무엘에게 이르시되 보라 내가 이스라엘 중에 한 일을 행하리니 그것을 듣는 자마다 두 귀가 울리리라"},{"n":12,"t":"내가 엘리의 집에 대하여 말한 것을 처음부터 끝까지 그 날에 그에게 다 이루리라"},{"n":13,"t":"내가 그 집을 영영토록 심판하겠다고 그에게 이른 것은 그의 아는 죄악을 인함이니 이는 그가 자기 아들들이 저주를 자청하되 금하지 아니하였음이니라"},{"n":14,"t":"그러므로 내가 엘리의 집에 대하여 맹세하기를 엘리 집의 죄악은 제물이나 예물로나 영영히 속함을 얻지 못하리라 하였노라"},{"n":15,"t":"사무엘이 아침까지 누웠다가 여호와의 집 문을 열었으나 그 이상을 엘리에게 알게 하기를 두려워하더니"},{"n":16,"t":"엘리가 사무엘을 불러 가로되 내 아들 사무엘아 하니 대답하되 내가 여기 있나이다"},{"n":17,"t":"가로되 네게 무엇을 말씀하셨느냐 청하노니 내게 숨기지 말라 네게 말씀하신 모든 것을 하나라도 숨기면 하나님이 네게 벌을 내리시고 또 내리시기를 원하노라"},{"n":18,"t":"사무엘이 세세히 말하고 조금도 숨기지 아니하니 그가 가로되 이는 여호와시니 선하신 소견대로 하실 것이니라 하니라"},{"n":19,"t":"사무엘이 자라매 여호와께서 그와 함께 계셔서 그 말로 하나도 땅에 떨어지지 않게 하시니"},{"n":20,"t":"단에서부터 브엘세바까지의 온 이스라엘이 사무엘은 여호와의 선지자로 세우심을 입은 줄을 알았더라"},{"n":21,"t":"여호와께서 실로에서 다시 나타나시되 여호와께서 실로에서 여호와의 말씀으로 사무엘에게 자기를 나타내시니"}],"kids":[]}},{"chapter":4,"title":"법궤를 빼앗기다","verses":{"krv":[{"n":1,"t":"사무엘의 말이 온 이스라엘에 전파되니라 이스라엘은 나가서 블레셋 사람과 싸우려고 에벤에셀 곁에 진 치고 블레셋 사람은 아벡에 진 쳤더니"},{"n":2,"t":"이스라엘을 대하여 항오를 벌이니라 그 둘이 싸우다가 이스라엘이 블레셋 사람 앞에서 패하여 그들에게 전쟁에서 죽임을 당한 군사가 사천 명 가량이라"},{"n":3,"t":"백성이 진으로 돌아오매 이스라엘 장로들이 가로되 여호와께서 어찌하여 우리로 오늘 블레셋 사람 앞에 패하게 하셨는고 여호와의 언약궤를 실로에서 우리에게로 가져다가 우리 중에 있게 하여 그것으로 우리를 우리 원수들의 손에서 구원하게 하자 하니"},{"n":4,"t":"이에 백성이 실로에 보내어 그룹 사이에 계신 만군의 여호와의 언약궤를 거기서 가져왔고 엘리의 두 아들 홉니와 비느하스는 하나님의 언약궤와 함께 거기 있었더라"},{"n":5,"t":"여호와의 언약궤가 진에 들어 올 때에 온 이스라엘이 큰 소리로 외치매 땅이 울린지라"},{"n":6,"t":"블레셋 사람이 그 외치는 소리를 듣고 가로되 히브리 진에서 큰 소리로 외침은 어찜이뇨 하다가 여호와의 궤가 진에 들어온 줄을 깨달은지라"},{"n":7,"t":"블레셋 사람이 두려워하여 가로되 신이 진에 이르렀도다 하고 또 가로되 우리에게 화로다 전일에는 이런 일이 없었도다"},{"n":8,"t":"우리에게 화로다 누가 우리를 이 능한 신들의 손에서 건지리요 그들은 광야에서 여러가지 재앙으로 애굽인을 친 신들이니라"},{"n":9,"t":"너희 블레셋 사람들아 강하게 되며 대장부가 되어라 너희가 히브리 사람의 종이 되기를 그들이 너희의 종이 되었던 것 같이 말고 대장부 같이 되어 싸우라 하고"},{"n":10,"t":"블레셋 사람이 쳤더니 이스라엘이 패하여 각기 장막으로 도망하였고 살륙이 심히 커서 이스라엘 보병의 엎드러진 자가 삼만이었으며"},{"n":11,"t":"하나님의 궤는 빼앗겼고 엘리의 두 아들 홉니와 비느하스는 죽임을 당하였더라"},{"n":12,"t":"당일에 어떤 베냐민 사람이 진에서 달려나와 그 옷을 찢고 그 머리에 티끌을 무릅쓰고 실로에 이르니라"},{"n":13,"t":"그가 이를 때는 엘리가 길 곁 자기 의자에 앉아 기다리며 그 마음이 여호와의 궤로 인하여 떨릴 즈음이라 그 사람이 성에 들어 오며 고하매 온 성이 부르짖는지라"},{"n":14,"t":"엘리가 그 부르짖는 소리를 듣고 가로되 이 훤화하는 소리는 어찜이뇨 그 사람이 빨리 와서 엘리에게 고하니"},{"n":15,"t":"때에 엘리의 나이 구십팔이라 그 눈이 어두워서 보지 못하더라"},{"n":16,"t":"그 사람이 엘리에게 고하되 나는 진 중에서 나온 자라 내가 오늘 진 중에서 도망하여 왔나이다 엘리가 가로되 내 아들아 일이 어찌 되었느냐"},{"n":17,"t":"소식을 전하는 자가 대답하여 가로되 이스라엘이 블레셋 사람 앞에서 도망하였고 백성 중에는 큰 살륙이 있었고 당신의 두 아들 홉니와 비느하스도 죽임을 당하였고 하나님의 궤는 빼앗겼나이다"},{"n":18,"t":"하나님의 궤를 말할 때에 엘리가 자기 의자에서 자빠져 문 곁에서 목이 부러져 죽었으니 나이 많고 비둔한 연고라 그가 이스라엘 사사가 된지 사십 년이었더라"},{"n":19,"t":"그의 며느리 비느하스의 아내가 잉태하여 산기가 가까웠더니 하나님의 궤 빼앗긴 것과 그 시부와 남편의 죽은 소문을 듣고 갑자기 아파서 몸을 구푸려 해산하고"},{"n":20,"t":"죽어갈 때에 곁에 섰던 여인들이 그에게 이르되 두려워 말라 네가 아들을 낳았다 하되 그가 대답지도 아니하며 관념치도 아니하고"},{"n":21,"t":"이르기를 영광이 이스라엘에서 떠났다 하고 아이 이름을 이가봇이라 하였으니 하나님의 궤가 빼앗겼고 그 시부와 남편이 죽었음을 인함이며"},{"n":22,"t":"또 이르기를 하나님의 궤를 빼앗겼으므로 영광이 이스라엘에서 떠났다 하였더라"}],"kids":[]}},{"chapter":5,"title":"블레셋 땅의 법궤","verses":{"krv":[{"n":1,"t":"블레셋 사람이 하나님의 궤를 빼앗아 가지고 에벤에셀에서부터 아스돗에 이르니라"},{"n":2,"t":"블레셋 사람이 하나님의 궤를 가지고 다곤의 당에 들어가서 다곤의 곁에 두었더니"},{"n":3,"t":"아스돗 사람이 이튿날 일찍이 일어나 본즉 다곤이 여호와의 궤 앞에서 엎드러져 그 얼굴이 땅에 닿았는지라 그들이 다곤을 일으켜 다시 그 자리에 세웠더니"},{"n":4,"t":"그 이튿날 아침에 그들이 일찍이 일어나 본즉 다곤이 여호와의 궤 앞에서 엎드러져 얼굴이 땅에 닿았고 그 머리와 두 손목은 끊어져 문지방에 있고 다곤의 몸둥이만 남았더라"},{"n":5,"t":"그러므로 다곤의 제사장들이나 다곤의 당에 들어가는 자는 오늘까지 아스돗에 있는 다곤의 문지방을 밟지 아니하더라"},{"n":6,"t":"여호와의 손이 아스돗 사람에게 엄중히 더하사 독종의 재앙으로 아스돗과 그 지경을 쳐서 망하게 하니"},{"n":7,"t":"아스돗 사람들이 이를 보고 가로되 이스라엘 신의 궤를 우리와 함께 있게 못할지라 그 손이 우리와 우리 신 다곤을 친다 하고"},{"n":8,"t":"이에 보내어 블레셋 사람의 모든 방백을 모으고 가로되 우리가 이스라엘 신의 궤를 어찌할꼬 그들이 대답하되 이스라엘 신의 궤를 가드로 옮겨가라 하므로 이스라엘 신의 궤를 옮겨 갔더니"},{"n":9,"t":"그것을 옮겨간 후에 여호와의 손이 심히 큰 환난을 그 성에 더하사 성읍 사람의 작은 자와 큰 자를 다 쳐서 독종이 나게 하신지라"},{"n":10,"t":"이에 그들이 하나님의 궤를 에그론으로 보내니라 하나님의 궤가 에그론에 이른즉 에그론 사람이 부르짖어 가로되 그들이 이스라엘 신의 궤를 우리에게로 가져다가 우리와 우리 백성을 죽이려 한다 하고"},{"n":11,"t":"이에 보내어 블레셋 모든 방백을 모으고 가로되 이스라엘 신의 궤를 보내어 본처로 돌아가게 하고 우리와 우리 백성 죽임을 면케 하자 하니 이는 온 성이 사망의 환난을 당함이라 거기서 하나님의 손이 엄중하시므로"},{"n":12,"t":"죽지 아니한 사람들은 독종으로 치심을 받아 성읍의 부르짖음이 하늘에 사무쳤더라"}],"kids":[]}},{"chapter":6,"title":"법궤가 돌아오다","verses":{"krv":[{"n":1,"t":"여호와의 궤가 블레셋 사람의 지방에 있은지 일곱 달이라"},{"n":2,"t":"블레셋 사람이 제사장들과 복술자들을 불러서 이르되 우리가 여호와의 궤를 어떻게 할꼬 그것을 어떻게 본처로 보낼 것을 우리에게 가르치라"},{"n":3,"t":"그들이 가로되 이스라엘 신의 궤를 보내려거든 거저 보내지 말고 그에게 속건제를 드려야 할지니라 그리하면 병도 낫고 그 손을 너희에게서 옮기지 아니하는 연고도 알리라"},{"n":4,"t":"그들이 가로되 무엇으로 그에게 드릴 속건제를 삼을꼬 가로되 블레셋 사람의 방백의 수효대로 금독종 다섯과 금쥐 다섯이라야 하리니 너희와 너희 방백에게 내린 재앙이 일반임이니라"},{"n":5,"t":"그러므로 너희는 너희 독종의 형상과 땅을 해롭게 하는 쥐의 형상을 만들어 이스라엘 신께 영화를 돌리라 그가 혹 그 손을 너희와 너희 신들과 너희 땅에서 경하게 하실까 하노라"},{"n":6,"t":"애굽인과 바로가 그 마음을 강퍅케 한 것 같이 어찌하여 너희가 너희 마음을 강퍅케 하겠느냐 그가 그들 중에서 기이하게 행한 후에 그들이 백성을 가게 하므로 백성이 떠나지 아니하였느냐"},{"n":7,"t":"그러므로 새 수레를 만들고 멍에 메어 보지 아니한 젖 나는 소 둘을 끌어다가 수레를 소에 메우고 그 송아지들은 떼어 집으로 돌려 보내고"},{"n":8,"t":"여호와의 궤를 가져다가 수레에 싣고 속건제 드릴 금 보물은 상자에 담아 궤 곁에 두고 그것을 보내어 가게 하고"},{"n":9,"t":"보아서 궤가 그 본 지경 길로 올라가서 벧세메스로 가면 이 큰 재앙은 그가 우리에게 내린 것이요 그렇지 아니하면 우리를 친 것이 그 손이 아니요 우연히 만난 것인 줄 알리라"},{"n":10,"t":"그 사람들이 그같이 하여 젖나는 소 둘을 끌어다가 수레를 메우고 송아지들은 집에 가두고"},{"n":11,"t":"여호와의 궤와 및 금쥐와 그들의 독종의 형상을 담은 상자를 수레 위에 실으니"},{"n":12,"t":"암소가 벧세메스 길로 바로 행하여 대로로 가며 갈 때에 울고 좌우로 치우치지 아니하였고 블레셋 방백들은 벧세메스 경계까지 따라 가니라"},{"n":13,"t":"벧세메스 사람들이 골짜기에서 밀을 베다가 눈을 들어 궤를 보고 그것의 보임을 기뻐하더니"},{"n":14,"t":"수레가 벧세메스 사람 여호수아의 밭 큰 돌 있는 곳에 이르러 선지라 무리가 수레의 나무를 패고 그 소를 번제로 여호와께 드리고"},{"n":15,"t":"레위인은 여호와의 궤와 그 궤와 함께 있는 금 보물 담긴 상자를 내려다가 큰 돌 위에 두매 그 날에 벧세메스 사람들이 여호와께 번제와 다른 제를 드리니라"},{"n":16,"t":"블레셋 다섯 방백이 이것을 보고 그 날에 에그론으로 돌아갔더라"},{"n":17,"t":"블레셋 사람이 여호와께 속건제로 드린 금독종은 이러하니 아스돗을 위하여 하나요 가사를 위하여 하나요 아스글론을 위하여 하나요 가드를 위하여 하나요 에그론을 위하여 하나이며"},{"n":18,"t":"드린 바 금쥐는 여호와의 궤를 놓은 큰 돌에 이르기까지의 모든 견고한 성읍과 시골 동리 곧 다섯 방백에게 속한 사람의 모든 성읍의 수효대로였더라 그 돌은 벧세메스 사람 여호수아의 밭에 오늘까지 있더라"},{"n":19,"t":"벧세메스 사람들이 여호와의 궤를 들여다 본고로 그들을 치사 (오만) 칠십 인을 죽이신지라 여호와께서 백성을 쳐서 크게 살륙하셨으므로 백성이 애곡하였더라"},{"n":20,"t":"벧세메스 사람들이 가로되 이 거룩하신 하나님 여호와 앞에 누가 능히 서리요 그를 우리에게서 뉘게로 가시게 할꼬 하고"},{"n":21,"t":"사자들을 기랏여아림 거민에게 보내어 가로되 블레셋 사람이 여호와의 궤를 도로 가져왔으니 너희는 내려와서 그것을 너희에게로 옮겨 가라"}],"kids":[]}},{"chapter":7,"title":"미스바의 회개","verses":{"krv":[{"n":1,"t":"기럇여아림 사람들이 와서 여호와의 궤를 옮겨 산에 사는 아비나답의 집에 들여 놓고 그 아들 엘리아살을 거룩히 구별하여 여호와의 궤를 지키게 하였더니"},{"n":2,"t":"궤가 기럇여아림에 들어간 날부터 이십 년 동안을 오래 있은지라 이스라엘 온 족속이 여호와를 사모하니라"},{"n":3,"t":"사무엘이 이스라엘 온 족속에게 일러 가로되 너희가 전심으로 여호와께 돌아오려거든 이방 신들과 아스다롯을 너희 중에서 제하고 너희 마음을 여호와께로 향하여 그만 섬기라 너희를 블레셋 사람의 손에서 건져내시리라"},{"n":4,"t":"이에 이스라엘 자손이 바알들과 아스다롯을 제하고 여호와만 섬기니라"},{"n":5,"t":"사무엘이 가로되 온 이스라엘은 미스바로 모이라 내가 너희를 위하여 여호와께 기도하리라 하매"},{"n":6,"t":"그들이 미스바에 모여 물을 길어 여호와 앞에 붓고 그 날에 금식하고 거기서 가로되 우리가 여호와께 범죄하였나이다 하니라 사무엘이 미스바에서 이스라엘 자손을 다스리니라"},{"n":7,"t":"이스라엘 자손이 미스바에 모였다 함을 블레셋 사람이 듣고 그 방백들이 이스라엘을 치러 올라온지라 이스라엘 자손이 듣고 블레셋 사람을 두려워하여"},{"n":8,"t":"사무엘에게 이르되 당신은 우리를 위하여 우리 하나님 여호와께 쉬지 말고 부르짖어 우리를 블레셋 사람의 손에서 구원하시게 하소서"},{"n":9,"t":"사무엘이 젖 먹는 어린 양을 취하여 온전한 번제를 여호와께 드리고 이스라엘을 위하여 여호와께 부르짖으매 여호와께서 응답하셨더라"},{"n":10,"t":"사무엘이 번제를 드릴 때에 블레셋 사람이 이스라엘과 싸우려고 가까이 오매 그 날에 여호와께서 블레셋 사람에게 큰 우뢰를 발하여 그들을 어지럽게 하시니 그들이 이스라엘 앞에 패한지라"},{"n":11,"t":"이스라엘 사람들이 미스바에서 나가서 블레셋 사람을 따라 벧갈 아래에 이르기까지 쳤더라"},{"n":12,"t":"사무엘이 돌을 취하여 미스바와 센 사이에 세워 가로되 여호와께서 여기까지 우리를 도우셨다 하고 그이름을 에벤에셀이라 하니라"},{"n":13,"t":"이에 블레셋 사람이 굴복하여 다시는 이스라엘 경내에 들어오지 못하였으며 여호와의 손이 사무엘의 사는 날 동안에 블레셋 사람을 막으시매"},{"n":14,"t":"블레셋 사람이 이스라엘에게서 빼앗았던 성읍이 에그론부터 가드까지 이스라엘에게 회복되니 이스라엘이 그 사방 지경을 블레셋 사람의 손에서 도로 찾았고 또 이스라엘과 아모리 사람 사이에 평화가 있었더라"},{"n":15,"t":"사무엘이 사는 날 동안에 이스라엘을 다스렸으되"},{"n":16,"t":"해마다 벧엘과 길갈과 미스바로 순회하여 그 모든 곳에서 이스라엘을 다스렸고"},{"n":17,"t":"라마로 돌아왔으니 이는 거기 자기 집이 있음이라 거기서도 이스라엘을 다스렸으며 또 거기 여호와를 위하여 단을 쌓았더라"}],"kids":[]}},{"chapter":8,"title":"왕을 요구하는 백성","verses":{"krv":[{"n":1,"t":"사무엘이 늙으매 그 아들들로 이스라엘 사사를 삼으니"},{"n":2,"t":"장자의 이름은 요엘이요 차자의 이름은 아비야라 그들이 브엘세바에서 사사가 되니라"},{"n":3,"t":"그 아들들이 그 아비의 행위를 따르지 아니하고 이를 따라서 뇌물을 취하고 판결을 굽게 하니라"},{"n":4,"t":"이스라엘 모든 장로가 모여 라마에 있는 사무엘에게 나아가서"},{"n":5,"t":"그에게 이르되 보소서 당신은 늙고 당신의 아들들은 당신의 행위를 따르지 아니하니 열방과 같이 우리에게 왕을 세워 우리를 다스리게 하소서 한지라"},{"n":6,"t":"우리에게 왕을 주어 우리를 다스리게 하라 한 그것을 사무엘이 기뻐하지 아니하여 여호와께 기도하매"},{"n":7,"t":"여호와께서 사무엘에게 이르시되 백성이 네게 한 말을 다 들으라 그들이 너를 버림이 아니요 나를 버려 자기들의 왕이 되지 못하게 함이니라"},{"n":8,"t":"내가 그들을 애굽에서 인도하여낸 날부터 오늘날까지 그들이 모든 행사로 나를 버리고 다른 신들을 섬김 같이 네게도 그리하는도다"},{"n":9,"t":"그러므로 그들의 말을 듣되 너는 그들에게 엄히 경계하고 그들을 다스릴 왕의 제도를 알게 하라"},{"n":10,"t":"사무엘이 왕을 구하는 백성에게 여호와의 모든 말씀을 일러"},{"n":11,"t":"가로되 너희를 다스릴 왕의 제도가 이러하니라 그가 너희 아들들을 취하여 그 병거와 말을 어거케 하리니 그들이 그 병거 앞에서 달릴 것이며"},{"n":12,"t":"그가 또 너희 아들들로 천부장과 오십부장을 삼을 것이며 자기 밭을 갈게 하고 자기 추수를 하게 할 것이며 자기 병거와 병거의 제구를 만들게 할 것이며"},{"n":13,"t":"그가 또 너희 딸들을 취하여 향료 만드는 자와 요리하는 자와 뗘굽는 자를 삼을 것이며"},{"n":14,"t":"그가 또 너희 밭과 포도원과 감람원의 제일 좋은 것을 취하여 자기 신하들에게 줄 것이며"},{"n":15,"t":"그가 또 너희 곡식과 포도원 소산의 십일조를 취하여 자기 관리와 신하에게 줄 것이며"},{"n":16,"t":"그가 또 너희 노비와 가장 아름다운 소년과 나귀들을 취하여 자기 일을 시킬 것이며"},{"n":17,"t":"너희 양떼의 십분 일을 취하리니 너희가 그 종이 될 것이라"},{"n":18,"t":"그 날에 너희가 너희 택한 왕을 인하여 부르짖되 그 날에 어호와께서 너희에게 응답지 아니하시리라"},{"n":19,"t":"백성이 사무엘의 말 듣기를 거절하여 가로되 아니로소이다 우리도 우리 왕이 있어야 하리니"},{"n":20,"t":"우리도 열방과 같이 되어 우리 왕이 우리를 다스리며 우리 앞에 나가서 우리의 싸움을 싸워야 할 것이니이다"},{"n":21,"t":"사무엘이 백성의 모든 말을 듣고 여호와께 고하매"},{"n":22,"t":"여호와께서 사무엘에게 이르시되 그들의 말을 들어 왕을 세우라 하시니 사무엘이 이스라엘 사람들에게 이르되 너희는 각기 성읍으로 돌아가라 하니라"}],"kids":[]}},{"chapter":9,"title":"사울을 만난 사무엘","verses":{"krv":[{"n":1,"t":"베냐민 지파에 기스라 이름하는 유력한 사람이 있으니 그는 아비엘의 아들이요 스롤의 손자요 베고랏의 증손이요 아비아의 현손이라 베냐민 사람이더라"},{"n":2,"t":"기스가 아들이 있으니 그 이름은 사울이요 준수한 소년이라 이스라엘 자손 중에 그보다 더 준수한 자가 없고 키는 모든 백성보다 어깨 위는 더하더라"},{"n":3,"t":"사울의 아비 기스가 암나귀들을 잃고 그 아들 사울에게 이르되 너는 한 사환을 데리고 일어나 가서 암나귀들을 찾으라 하매"},{"n":4,"t":"그가 에브라임 산지와 살리사 땅으로 두루 다니되 찾지 못하고 사알림 땅으로 두루 다니되 없고 베냐민 사람의 땅으로 두루 다니되 찾지 못하니라"},{"n":5,"t":"그들이 숩 땅에 이른 때에 사울이 함께 하는 사환에게 이르되 돌아가자 내 부친이 암나귀 생각은 고사하고 우리를 위하여 걱정하실까 두려워하노라"},{"n":6,"t":"대답하되 보소서 이 성에 하나님의 사람이 있는데 존중히 여김을 받는 사람이라 그가 말한 것은 반드시 다 응하나니 그리로 가사이다 그가 혹 우리의 갈 길을 가르칠까 하나이다"},{"n":7,"t":"사울이 그 사환에게 이르되 우리가 가면 그 사람에게 무엇을 드리겠느냐 우리 그릇에 식물이 다하였으니 하나님의 사람에게 드릴 예물이 없도다 무엇이 있느냐"},{"n":8,"t":"사환이 사울에게 다시 대답하여 가로되 보소서 내 손에 은 한 세겔의 사분 일이 있으니 하나님의 사람에게 드려 우리 길을 가르치게 하겠나이다"},{"n":9,"t":"(옛적 이스라엘에 사람이 하나님께 가서 물으려 하면 말하기를 선견자에게로 가자 하였으니 지금 선지자라 하는 자를 옛적에는 선견자라 일컬었더라)"},{"n":10,"t":"사울이 그 사환에게 이르되 네 말이 옳다 가자 하고 그들이 하나님의 사람 있는 성으로 가니라"},{"n":11,"t":"그들이 성을 향한 비탈길로 올라가다가 물 길러 나오는 소녀들을 만나 그들에게 묻되 선견자가 여기 있느냐"},{"n":12,"t":"그들이 대답하여 가로되 있나이다 보소서 그가 당신보다 앞섰으니 빨리 가소서 백성이 오늘 산당에서 제사를 드리므로 그가 오늘 성에 들어오셨나이다"},{"n":13,"t":"당신들이 성으로 들어가면 그가 먹으러 산당에 올라가기 전에 곧 만나리이다 그가 오기 전에는 백성이 먹지 아니하나니 이는 그가 제물을 축사한 후에야 청함을 받은 자가 먹음이라 그러므로 지금 올라가소서 금시로 만나리이다 하는지라"},{"n":14,"t":"그들이 성읍으로 올라가서 그리로 들어갈 때에 사무엘이 마침 산당으로 올라가려고 마주 나오더라"},{"n":15,"t":"사울의 오기 전 날에 여호와께서 사무엘에게 알게 하여 가라사대"},{"n":16,"t":"내일 이맘 때에 내가 베냐민 땅에서 한 사람을 네게 보내리니 너는 그에게 기름을 부어 내 백성 이스라엘의 지도자를 삼으라 그가 내 백성을 블레셋 사람의 손에서 구원하리라 내 백성의 부르짖음이 내게 상달하였으므로 내가 그들을 돌아 보았노라 하시더니"},{"n":17,"t":"사무엘이 사울을 볼 때에 여호와께서 그에게 이르시되 보라 이는 내가 네게 말한 사람이니 이가 내 백성을 통할하리라 하시니라"},{"n":18,"t":"사울이 성문 가운데 사무엘에게 나아가 가로되 선견자의 집이 어디인지 청컨대 내게 가르치소서"},{"n":19,"t":"사무엘이 사울에게 대답하여 가로되 내가 선견자니라 너는 내 앞서 산당으로 올라가라 너희가 오늘날 나와 함께 먹을 것이요 아침에는 내가 너를 보내되 네 마음에 있는 것을 다 네게 말하리라"},{"n":20,"t":"사흘 전에 잃은 네 암나귀들을 염려하지 말라 찾았느니라 온 이스라엘의 사모하는 자가 누구냐 너와 네 아비의 온 집이 아니냐"},{"n":21,"t":"사울이 대답하여 가로되 나는 이스라엘 지파의 가장 작은 지파 베냐민 사람이 아니오며 나의 가족은 베냐민 지파 모든 가족 중에 가장 미약하지 아니하니이까 당신이 어찌하여 내게 이같이 말씀하시나이까"},{"n":22,"t":"사무엘이 사울과 그 사환을 인도하여 객실로 들어가서 청한 자 중 수석에 앉게 하였는데 객은 삼십 명 가량이었더라"},{"n":23,"t":"사무엘이 요리인에게 이르되 내가 네게 주며 네게 두라고 말한 그 부분을 가져오라"},{"n":24,"t":"요리인이 넓적다리와 그것에 붙은 것을 가져다가 사울 앞에 놓는지라 사무엘이 가로되 보라 이는 두었던 것이니 네 앞에 놓고 먹으라 내가 백성을 청할 때부터 너를 위하여 이것을 두어서 이때를 기다리게 하였느니라 그 날에 사울이 사무엘과 함께 먹으니라"},{"n":25,"t":"그들이 산당에서 내려 성에 들어가서는 사무엘이 사울과 함께 지붕에서 담화하고"},{"n":26,"t":"그들이 일찍이 일어날새 동틀 때 즈음이라 사무엘이 지붕에서 사울을 불러 가로되 일어나라 내가 너를 보내리라 하매 사울이 일어나고 그 두 사람 사울과 사무엘이 함께 밖으로 나가서"},{"n":27,"t":"성읍 끝에 이르매 사무엘이 사울에게 이르되 사환으로 우리를 앞서게 하라 사환이 앞서매 또 가로되 너는 이제 잠간 서 있으라 내가 하나님의 말씀을 네게 들리리라"}],"kids":[]}},{"chapter":10,"title":"사울을 왕으로 세움","verses":{"krv":[{"n":1,"t":"이에 사무엘이 기름병을 취하여 사울의 머리에 붓고 입맞추어 가로되 여호와께서 네게 기름을 부으사 그 기업의 지도자를 삼지 아니하셨느냐"},{"n":2,"t":"네가 오늘 나를 떠나가다가 베냐민 경계 셀사에 있는 라헬의 묘실 곁에서 두 사람을 만나리니 그들이 네게 이르기를 네가 찾으러 갔던 암나귀들을 찾은지라 네 아비가 암나귀들의 염려는 놓았으나 너희를 인하여 걱정하여 가로되 내 아들을 위하여 어찌하리요 하더라 할 것이요"},{"n":3,"t":"네가 거기서 더 나아가서 다볼 상수리나무에 이르면 거기서 하나님께 뵈려고 벧엘로 올라가는 세 사람이 너와 만나리니 하나는 염소 새끼 셋을 이끌었고 하나는 떡 세덩이를 가졌고 하나는 포도주 한 가죽부대를 가진 자라"},{"n":4,"t":"그들이 네게 문안하고 떡 두 덩이를 주겠고 너는 그 손에서 받으리라"},{"n":5,"t":"그 후에 네가 하나님의 산에 이르리니 그곳에는 블레셋 사람의 영문이 있느니라 네가 그리로 가서 그 성읍으로 들어갈 때에 선지자의 무리가 산당에서부터 비파와 소고와 저와 수금을 앞세우고 예언하며 내려오는 것을 만날 것이요"},{"n":6,"t":"네게는 여호와의 신이 크게 임하리니 너도 그들과 함께 예언을 하고 변하여 새 사람이 되리라"},{"n":7,"t":"이 징조가 네게 임하거든 너는 기회를 따라 행하라 하나님이 너와 함께 하시느니라"},{"n":8,"t":"너는 나보다 앞서 길갈로 내려가라 내가 네게로 내려가서 번제와 화목제를 드리리니 내가 네게 가서 너의 행할 것을 가르칠 때까지 칠 일을 기다리라"},{"n":9,"t":"그가 사무엘에게서 떠나려고 몸을 돌이킬 때에 하나님이 새 마음을 주셨고 그 날 그 징조도 다 응하니라"},{"n":10,"t":"그들이 산에 이를 때에 선지자의 무리가 그를 영접하고 하나님의 신이 사울에게 크게 임하므로 그가 그들 중에서 예언을 하니"},{"n":11,"t":"전에 사울을 알던 모든 사람이 사울의 선지자들과 함께 예언함을 보고 서로 이르되 기스의 아들의 당한 일이 무엇이뇨 사울도 선지자들 중에 있느냐 하고"},{"n":12,"t":"그곳의 어떤 사람은 말하여 이르되 그들의 아비가 누구냐 한지라 그러므로 속담이 되어 가로되 사울도 선지자들 중에 있느냐 하더라"},{"n":13,"t":"사울이 예언하기를 마치고 산당으로 가니라"},{"n":14,"t":"사울의 숙부가 사울과 그 사환에게 이르되 너희가 어디로 갔더냐 사울이 가로되 암나귀들을 찾다가 얻지 못하므로 사무엘에게 갔었나이다"},{"n":15,"t":"사울의 숙부가 가로되 청하노니 사무엘이 너희에게 이른 말을 내게 고하라"},{"n":16,"t":"사울이 그 숙부에게 말하되 그가 암나귀들을 찾았다고 우리에게 분명히 말하더이다 하고 사무엘의 말하던 나라의 일은 고하지 아니하니라"},{"n":17,"t":"사무엘이 백성을 미스바로 불러 여호와 앞에 모으고"},{"n":18,"t":"이스라엘 자손에게 이르되 이스라엘 하나님 여호와께서 이같이 말씀하시기를 내가 이스라엘을 애굽에서 인도하여 내고 너희를 애굽인의 손과 너희를 압제하는 모든 나라의 손에서 건져내었느니라 하셨거늘"},{"n":19,"t":"너희가 너희를 모든 재난과 고통 중에서 친히 구원하여 내신 너희 하나님을 오늘날 버리고 이르기를 우리 위에 왕을 세우라 하도다 그런즉 이제 너희 지파대로 천 명씩 여호와 앞에 나아오라 하고"},{"n":20,"t":"사무엘이 이에 이스라엘 모든 지파를 가까이 오게 하였더니 베냐민 지파가 뽑혔고"},{"n":21,"t":"베냐민 지파를 그 가족대로 가까이 오게 하였더니 마드리의 가족이 뽑혔고 그 중에서 기스의 아들 사울이 뽑혔으나 그를 찾아도 만나지 못한지라"},{"n":22,"t":"그러므로 그들이 또 여호와께 묻되 그 사람이 여기 왔나이까 여호와께서 대답하시되 그가 행구 사이에 숨었느니라"},{"n":23,"t":"그들이 달려가서 거기서 데려오매 그가 백성 중에 서니 다른 사람보다 어깨 위나 더 크더라"},{"n":24,"t":"사무엘이 모든 백성에게 이르되 너희는 여호와의 택하신 자를 보느냐 모든 백성 중에 짝할 이가 없느니라 하니 모든 백성이 왕의 만세를 외쳐 부르니라"},{"n":25,"t":"사무엘이 나라의 제도를 백성에게 말하고 책에 기록하여 여호와 앞에 두고 모든 백성을 각기 집으로 보내매"},{"n":26,"t":"사울도 기브아 자기 집으로 갈 때에 마음이 하나님께 감동된 유력한 자들은 그와 함께 갔어도"},{"n":27,"t":"어떤 비류는 가로되 이 사람이 어떻게 우리를 구원하겠느냐 하고 멸시하며 예물을 드리지 아니하니라 그러나 그는 잠잠하였더라"}],"kids":[]}},{"chapter":11,"title":"사울의 첫 승리, 암몬","verses":{"krv":[{"n":1,"t":"암몬 사람 나하스가 올라와서 길르앗 야베스를 대하여 진 치매 야베스 모든 사람이 나하스에게 이르되 우리와 언약하자 그리하면 우리가 너를 섬기리라"},{"n":2,"t":"암몬 사람 나하스가 그들에게 이르되 내가 너희 오른눈을 다 빼어야 너희와 언약하리라 내가 온 이스라엘을 이같이 모욕하리라"},{"n":3,"t":"야베스 장로들이 이르되 우리에게 이레 유예를 주어 우리로 이스라엘 온 지경에 사자를 보내게 하라 우리를 구원할 자가 없으면 네게 나아가리라 하니라"},{"n":4,"t":"이에 사자가 사울의 기브아에 이르러 이 말을 백성에게 고하매 모든 백성이 소리를 높여 울더니"},{"n":5,"t":"마침 사울이 밭에서 소를 몰고 오다가 가로되 백성이 무슨 일로 우느냐 그들이 야베스 사람의 말로 고하니라"},{"n":6,"t":"사울이 이 말을 들을 때에 하나님의 신에게 크게 감동되매 그 노가 크게 일어나서"},{"n":7,"t":"한 겨리 소를 취하여 각을 뜨고 사자의 손으로 그것을 이스라엘 모든 지경에 두루 보내어 가로되 누구든지 나와서 사울과 사무엘을 좇지 아니하면 그 소들도 이와 같이 하리라 하였더니 여호와의 두려움이 백성에게 임하매 그들이 한 사람 같이 나온지라"},{"n":8,"t":"사울이 베섹에서 그들을 계수하니 이스라엘 자손이 삼십만이요 유다 사람이 삼만이더라"},{"n":9,"t":"무리가 온 사자들에게 이르되 너희는 길르앗 야베스 사람에게 이같이 이르기를 내일 해가 더울 때에 너희가 구원을 얻으리라 하라 사자들이 돌아가서 야베스 사람들에게 고하매 그들이 기뻐하니라"},{"n":10,"t":"야베스 사람들이 이에 가로되 우리가 내일 너희에게 나아가리니 너희 소견에 좋을 대로 우리에게 다 행하라 하니라"},{"n":11,"t":"이튿날에 사울이 백성을 삼 대에 나누고 새벽에 적진 중에 들어가서 날이 더울 때까지 암몬 사람을 치매 남은 자가 다 흩어져서 둘도 함께 한 자가 없었더라"},{"n":12,"t":"백성이 사무엘에게 이르되 사울이 어찌 우리를 다스리겠느냐 한 자가 누구니이까 그들을 끌어내소서 우리가 죽이겠나이다"},{"n":13,"t":"사울이 가로되 이 날에는 사람을 죽이지 못하리니 여호와께서 오늘날 이스라엘 중에 구원을 베푸셨음이니라"},{"n":14,"t":"사무엘이 백성에게 이르되 오라 우리가 길갈로 가서 나라를 새롭게 하자"},{"n":15,"t":"모든 백성이 길갈로 가서 거기서 여호와 앞에 사울로 왕을 삼고 거기서 여호와 앞에 화목제를 드리고 사울과 이스라엘 모든 사람이 거기서 크게 기뻐하니라"}],"kids":[]}},{"chapter":12,"title":"사무엘의 고별 설교","verses":{"krv":[{"n":1,"t":"사무엘이 온 이스라엘에게 이르되 보라 너희가 내게 한 말을 내가 다 듣고 너희 위에 왕을 세웠더니"},{"n":2,"t":"이제 왕이 너희 앞에 출입하느니라 보라 나는 늙어 머리가 희었고 내 아들들도 너희와 함께 있느니라 내가 어려서부터 오늘날까지 너희 앞에 출입하였거니와"},{"n":3,"t":"내가 여기 있나니 여호와 앞과 그 기름 부음을 받은 자 앞에서 내게 대하여 증거하라 내가 뉘 소를 취하였느냐 뉘 나귀를 취하였느냐 누구를 속였느냐 누구를 압제하였느냐 내 눈을 흐리게 하는 뇌물을 뉘 손에서 취하였느냐 그리하였으면 내가 그것을 너희에게 갚으리라"},{"n":4,"t":"그들이 가로되 당신이 우리를 속이지 아니하였고 압제하지 아니하였고 뉘 손에서 아무 것도 취한 것이 없나이다"},{"n":5,"t":"사무엘이 백성에게 이르되 너희가 내 손에서 아무 것도 찾아낸 것이 없음을 여호와께서 너희에게 대하여 증거하시며 그 기름 부음을 받은 자도 오늘날 증거하느니라 그들이 가로되 그가 증거하시나이다"},{"n":6,"t":"사무엘이 백성에게 이르되 모세와 아론을 세우시며 너희 열조를 애굽 땅에서 인도하여 내신 이는 여호와시니"},{"n":7,"t":"그런즉 가만히 섰으라 여호와께서 너희와 너희 열조에게 행하신 모든 의로운 일에 대하여 내가 여호와 앞에서 너희와 담론하리라"},{"n":8,"t":"야곱이 애굽에 들어간 후 너희 열조가 여호와께 부르짖으매 여호와께서 모세와 아론을 보내사 그 두 사람으로 너희 열조를 애굽에서 인도하여 내어 이곳에 거하게 하셨으나"},{"n":9,"t":"그들이 그 하나님 여호와를 잊은지라 여호와께서 그들을 하솔 군장 시스라의 손과 블레셋 사람의 손과 모압 왕의 손에 붙이셨더니 그들이 치매"},{"n":10,"t":"백성이 여호와께 부르짖어 가로되 우리가 여호와를 버리고 바알들과 아스다롯을 섬기므로 범죄하였나이다 그러하오나 이제 우리를 원수들의 손에서 건져 내소서 그리하시면 우리가 주를 섬기겠나이다 하매"},{"n":11,"t":"여호와께서 여룹바알과 베단과 입다와 나 사무엘을 보내사 너희를 너희 사방 원수의 손에서 건져내사 너희로 안전히 거하게 하셨거늘"},{"n":12,"t":"너희가 암몬 자손의 왕 나하스의 너희를 치러 옴을 보고 너희 하나님 여호와께서는 너희의 왕이 되실지라도 너희가 내게 이르기를 아니라 우리를 다스릴 왕이 있어야 하겠다 하였도다"},{"n":13,"t":"이제 너희의 구한 왕 너희의 택한 왕을 보라 여호와께서 너희 위에 왕을 세우셨느니라"},{"n":14,"t":"너희가 만일 여호와를 경외하여 그를 섬기며 그 목소리를 듣고 여호와의 명령을 거역하지 아니하며 또 너희와 너희를 다스리는 왕이 너희 하나님 여호와를 좇으면 좋으니라마는"},{"n":15,"t":"너희가 만일 여호와의 목소리를 듣지 아니하고 여호와의 명령을 거역하면 여호와의 손이 너희의 열조를 치신 것 같이 너희를 치실 것이라"},{"n":16,"t":"너희는 이제 가만히 서서 여호와께서 너희 목전에 행하시는 이 큰 일을 보라"},{"n":17,"t":"오늘은 밀 베는 때가 아니냐 내가 여호와께 아뢰리니 여호와께서 우뢰와 비를 보내사 너희가 왕을 구한 일 곧 여호와의 목전에 범한 죄악이 큼을 너희로 밝히 알게 하시리라"},{"n":18,"t":"이에 사무엘이 여호와께 아뢰매 여호와께서 그 날에 우뢰와 비를 보내시니 모든 백성이 여호와와 사무엘을 크게 두려워하니라"},{"n":19,"t":"모든 백성이 사무엘에게 이르되 당신의 종들을 위하여 당신의 하나님 여호와께 기도하여 우리로 죽지 않게 하소서 우리가 우리의 모든 죄에 왕을 구하는 악을 더하였나이다"},{"n":20,"t":"사무엘이 백성에게 이르되 두려워 말라 너희가 과연 이 모든 악을 행하였으나 여호와를 좇는데서 돌이키지 말고 오직 너희 마음을 다하여 여호와를 섬기라"},{"n":21,"t":"돌이켜 유익하게도 못하며 구원하지도 못하는 헛된 것을 좇지 말라 그들은 헛되니라"},{"n":22,"t":"여호와께서는 너희로 자기 백성 삼으신 것을 기뻐하신 고로 그 크신 이름을 인하여 자기 백성을 버리지 아니하실 것이요"},{"n":23,"t":"나는 너희를 위하여 기도하기를 쉬는 죄를 여호와 앞에 결단코 범치 아니하고 선하고 의로운 도로 너희를 가르칠 것인즉"},{"n":24,"t":"너희는 여호와께서 너희를 위하여 행하신 그 큰 일을 생각하여 오직 그를 경외하며 너희의 마음을 다하여 진실히 섬기라"},{"n":25,"t":"만일 너희가 여전히 악을 행하면 너희와 너희 왕이 다 멸망하리라"}],"kids":[]}},{"chapter":13,"title":"사울의 성급한 제사","verses":{"krv":[{"n":1,"t":"사울이 왕이 될 때에 사십 세라 그가 이스라엘을 다스린지 이년에"},{"n":2,"t":"이스라엘 사람 삼천을 택하여 그 중에서 이천은 자기와 함께 믹마스와 벧엘 산에 있게 하고 일천은 요나단과 함께 베냐민 기브아에 있게 하고 남은 백성은 각기 장막으로 보내니라"},{"n":3,"t":"요나단이 게바에 있는 블레셋 사람의 수비대를 치매 블레셋 사람이 이를 들은지라 사울이 온 땅에 나팔을 불어 이르되 히브리 사람들은 들으라 하니"},{"n":4,"t":"온 이스라엘이 사울의 블레셋 사람의 수비대를 친 것과 이스라엘이 블레셋 사람의 가증히 여김이 되었다 함을 듣고 길갈로 모여 사울을 좇으니라"},{"n":5,"t":"블레셋 사람이 이스라엘과 싸우려 하여 모였는데 병거가 삼만이요 마병이 육천이요 백성은 해변의 모래 같이 많더라 그들이 올라와서 벧아웬 동편 믹마스에 진 치매"},{"n":6,"t":"이스라엘 사람들이 위급함을 보고 절박하여 굴과 수풀과 바위틈과 은밀한 곳과 웅덩이에 숨으며"},{"n":7,"t":"어떤 히브리 사람들은 요단을 건너 갓과 길르앗 땅으로 가되 사울은 아직 길갈에 있고 그를 좇은 모든 백성은 떨더라"},{"n":8,"t":"사울이 사무엘의 정한 기한대로 이레를 기다리되 사무엘이 길갈로 오지 아니하매 백성이 사울에게서 흩어지는지라"},{"n":9,"t":"사울이 가로되 번제와 화목제물을 이리로 가져오라 하여 번제를 드렸더니"},{"n":10,"t":"번제 드리기를 필하자 사무엘이 온지라 사울이 나가 맞으며 문안하매"},{"n":11,"t":"사무엘이 가로되 왕의 행한 것이 무엇이뇨 사울이 가로되 백성은 나에게서 흩어지고 당신은 정한 날 안에 오지 아니하고 블레셋 사람은 믹마스에 모였음을 내가 보았으므로"},{"n":12,"t":"이에 내가 이르기를 블레셋 사람은 나를 치러 길갈로 내려오겠거늘 내가 여호와께 은혜를 간구치 못하였다 하고 부득이하여 번제를 드렸나이다"},{"n":13,"t":"사무엘이 사울에게 이르되 왕이 망령되이 행하였도다 왕이 왕의 하나님 여호와께서 왕에게 명하신 명령을 지키지 아니하였도다 그리하였더면 여호와께서 이스라엘 위에 왕의 나라를 영영히 세우셨을 것이어늘"},{"n":14,"t":"지금은 왕의 나라가 길지 못할 것이라 여호와께서 왕에게 명하신 바를 왕이 지키지 아니하였으므로 여호와께서 그 마음에 맞는 사람을 구하여 그 백성의 지도자를 삼으셨느니라 하고"},{"n":15,"t":"사무엘이 일어나 길갈에서 떠나 베냐민 기브아로 올라가니라 사울이 자기와 함께 한 백성을 계수하니 육백 명 가량이라"},{"n":16,"t":"사울과 그 아들 요나단과 그들과 함께한 백성은 베냐민 게바에 있고 블레셋 사람은 믹마스에 진 쳤더니"},{"n":17,"t":"노략꾼들이 삼 대로 블레셋 사람의 진에서 나와서 한 대는 오브라길로 말미암아 수알 땅에 이르렀고"},{"n":18,"t":"한 대는 벧호론 길로 향하였고 한 대는 광야를 향한 스보임 골짜기가 내려다 보이는 지경 길로 향하였더라"},{"n":19,"t":"때에 이스라엘 온 땅에 철공이 없어졌으니 이는 블레셋 사람이 말하기를 히브리 사람이 칼이나 창을 만들까 두렵다 하였음이라"},{"n":20,"t":"온 이스라엘 사람이 각기 보습이나 삽이나 도끼나 괭이를 벼리려면 블레셋 사람에게로 내려갔었는데"},{"n":21,"t":"곧 그들이 괭이나 삽이나 쇠스랑이나 도끼나 쇠채찍이 무딜 때에 그리하였으므로"},{"n":22,"t":"싸우는 날에 사울과 요나단과 함께한 백성의 손에는 칼이나 창이 없고 오직 사울과 그 아들 요나단에게만 있으니라"},{"n":23,"t":"블레셋 사람의 부대가 나와서 믹마스 어귀에 이르렀더라"}],"kids":[]}},{"chapter":14,"title":"요나단의 믿음과 사울의 맹세","verses":{"krv":[{"n":1,"t":"하루는 사울의 아들 요나단이 자기 병기를 든 소년에게 이르되 우리가 건너편 블레셋 사람의 부대에게로 건너가자 하고 그 아비에게는 고하지 아니하였더라"},{"n":2,"t":"사울이 기브아 변경 미그론에 있는 석류나무 아래 머물렀고 함께한 백성은 육백 명 가량이며"},{"n":3,"t":"아히야는 에봇을 입고 거기 있었으니 그는 이가봇의 형제 아히둡의 아들이요 비느하스의 손자요 실로에서 여호와의 제사장이 되었던 엘리의 증손이었더라 백성은 요나단의 간 줄을 알지 못하니라"},{"n":4,"t":"요나단이 블레셋 사람의 부대에게로 건너가려 하는 어귀 사이 이편에도 험한 바위가 있고 저편에도 험한 바위가 있는데 하나의 이름은 보세스요 하나의 이름은 세네라"},{"n":5,"t":"한 바위는 북에서 믹마스 앞에 일어섰고 하나는 남에서 게바 앞에 일어섰더라"},{"n":6,"t":"요나단이 자기 병기 든 소년에게 이르되 우리가 이 할례 없는 자들의 부대에게로 건너가자 여호와께서 우리를 위하여 일하실까 하노라 여호와의 구원은 사람의 많고 적음에 달리지 아니하였느니라"},{"n":7,"t":"병기 든 자가 그에게 이르되 당신의 마음에 있는 대로 다 행하여 앞서 가소서 내가 당신과 마음을 같이하여 따르리이다"},{"n":8,"t":"요나단이 가로되 보라 우리가 그 사람들에게로 건너가서 그들에게 보이리니"},{"n":9,"t":"그들이 만일 이같이 우리에게 이르기를 우리가 너희에게로 가기를 기다리라 하면 우리는 우리 곳에 가만히 서서 그들에게로 올라가지 말 것이요"},{"n":10,"t":"그들이 만일 이같이 말하기를 우리에게로 올라오라 하면 우리가 올라갈 것은 여호와께서 그들을 우리 손에 붙이셨음이니 이것이 우리에게 표징이 되리라 하고"},{"n":11,"t":"둘이 다 블레셋 사람의 부대에게 보이매 블레셋 사람이 가로되 보라 히브리 사람이 그 숨었던 구멍에서 나온다 하고"},{"n":12,"t":"그 부대 사람들이 요나단과 그 병기 든 자를 대하여 가로되 우리에게로 올라오라 너희에게 한 일을 보이리라 한지라 요나단이 자기 병기 든 자에게 이르되 나를 따라 올라오라 여호와께서 그들을 이스라엘의 손에 붙이셨느니라 하고"},{"n":13,"t":"요나단이 손발로 붙잡고 올라갔고 그 병기 든 자도 따랐더라 블레셋 사람들이 요나단 앞에서 엎드러지매 병기 든 자가 따라가며 죽였으니"},{"n":14,"t":"요나단과 그 병기 든 자가 반일경 지단 안에서 처음으로 도륙한 자가 이십 인 가량이라"},{"n":15,"t":"들에 있는 진과 모든 백성 중에 떨림이 일어났고 부대와 노략꾼들도 떨었으며 땅도 진동하였으니 이는 큰 떨림이었더라"},{"n":16,"t":"베냐민 기브아에 있는 사울의 파수꾼이 바라본즉 허다한 블레셋 사람이 무너져 이리저리 흩어지더라"},{"n":17,"t":"사울이 자기와 함께 한 백성에게 이르되 우리에게서 누가 나갔는지 점고하여 보라 하고 점고한즉 요나단과 그의 병기 든 자가 없어졌더라"},{"n":18,"t":"사울이 아히야에게 이르되 하나님의 궤를 이리로 가져오라 하니 그 때에 하나님의 궤가 이스라엘 자손과 함께 있음이라"},{"n":19,"t":"사울이 제사장에게 말할 때에 블레셋 사람의 진에 소동이 점점 더한지라 사울이 제사장에게 이르되 네 손을 거두라 하고"},{"n":20,"t":"사울과 그와 함께한 모든 백성이 모여 전장에 가서 본즉 블레셋 사람이 각각 칼로 그 동무를 치므로 크게 혼란하였더라"},{"n":21,"t":"전에 블레셋 사람과 함께 하던 히브리 사람이 사방에서 블레셋 사람과 함께 와서 진에 들어왔더니 그들이 돌이켜 사울과 요나단과 함께한 이스라엘 사람과 합하였고"},{"n":22,"t":"에브라임 산지에 숨었던 이스라엘 모든 사람도 블레셋 사람의 도망함을 듣고 싸우러 나와서 그들을 추격하였더라"},{"n":23,"t":"여호와께서 그 날에 이스라엘을 구원하시므로 전쟁이 벧아웬을 지나니라"},{"n":24,"t":"이 날에 이스라엘 백성이 피곤하였으니 이는 사울이 백성에게 맹세시켜 경계하여 이르기를 저녁 곧 내가 내 원수에게 보수하는 때까지 아무 식물이든지 먹는 사람은 저주를 받을지어다 하였음이라 그러므로 백성이 식물을 맛보지 못하고"},{"n":25,"t":"그들이 다 수풀에 들어간즉 땅에 꿀이 있더라"},{"n":26,"t":"백성이 수풀로 들어갈 때에 꿀이 흐르는 것을 보고도 그들이 맹세를 두려워하여 손을 그 입에 대는 자가 없으나"},{"n":27,"t":"요나단은 그 아비가 맹세로 백성에게 명할 때에 듣지 못하였으므로 손에 가진 지팡이 끝을 내밀어 꿀을 찍고 그 손을 돌이켜 입에 대매 눈이 밝아졌더라"},{"n":28,"t":"때에 백성 중 하나가 고하여 가로되 당신의 부친이 맹세로 백성에게 엄히 명하여 말씀하시기를 오늘날 식물을 먹는 사람은 저주를 받을지어다 하셨나이다 그러므로 백성이 피곤하였나이다"},{"n":29,"t":"요나단이 가로되 내 부친이 이 땅으로 곤란케 하셨도다 보라 내가 이 꿀 조금을 맛보고도 내 눈이 이렇게 밝았거든"},{"n":30,"t":"하물며 백성이 오늘 그 대적에게서 탈취하여 얻은 것을 임의로 먹었더면 블레셋 사람을 살륙함이 더욱 많지 아니하였겠느냐"},{"n":31,"t":"그 날에 백성이 믹마스에서부터 아얄론에 이르기까지 블레셋 사람을 쳤으므로 그들이 심히 피곤한지라"},{"n":32,"t":"백성이 이에 탈취한 물건에 달려가서 양과 소와 송아지들을 취하고 그것을 땅에서 잡아 피 있는 채 먹었더니"},{"n":33,"t":"무리가 사울에게 고하여 가로되 보소서 백성이 고기를 피채 먹어 여호와께 범죄하였나이다 사울이 가로되 너희가 무신하게 행하였도다 이제 큰 돌을 내게로 굴려오라 하고"},{"n":34,"t":"또 가로되 너희는 백성 중에 흩어져 다니며 이르기를 사람은 각기 소와 각기 양을 이리로 끌어다가 잡아 먹되 피 있는 채 먹어서 여호와께 범죄하지 말라 하매 그 밤에 모든 백성이 각각 자기의 소를 끌어다가 거기서 잡으니라"},{"n":35,"t":"사울이 여호와를 위하여 단을 쌓았으니 이는 그가 여호와를 위하여 처음 쌓은 단이었더라"},{"n":36,"t":"사울이 가로되 우리가 밤에 블레셋 사람을 쫓아 내려가서 동틀 때까지 그들 중에서 탈취하고 한 사람도 남기지 말자 무리가 가로대 왕의 소견에 좋은 대로 하소서 할 때에 제사장이 가로되 이리로 와서 하나님께로 나아가사이다 하매"},{"n":37,"t":"사울이 하나님께 묻자오되 내가 블레셋 사람을 쫓아 내려가리이까 주께서 그들을 이스라엘의 손에 붙이시겠나이까 하되 그 날에 대답지 아니하시는지라"},{"n":38,"t":"사울이 가로되 너희 백성의 어른들아 다 이리로 오라 오늘 이 죄가 뉘게 있나 알아 보자"},{"n":39,"t":"이스라엘을 구원하신 여호와의 사심으로 맹세하노니 내 아들 요나단에게 있다 할지라도 반드시 죽으리라 하되 모든 백성 중 한 사람도 대답지 아니하매"},{"n":40,"t":"이에 그가 온 이스라엘에게 이르되 너희는 저편에 있으라 나와 내 아들 요나단은 이편에 있으리라 백성이 사울에게 말하되 왕의 소견에 좋은 대로 하소서 하니라"},{"n":41,"t":"이에 사울이 이스라엘의 하나님 여호와께 아뢰되 원컨대 실상을 보이소서 하였더니 요나단과 사울이 뽑히고 백성은 면한지라"},{"n":42,"t":"사울이 가로되 나와 내 아들 요나단 사이에 뽑으라 하였더니 요나단이 뽑히니라"},{"n":43,"t":"사울이 요나단에게 가로되 너의 행한 것을 내게 고하라 요나단이 고하여 가로되 내가 다만 내 손에 가진 지팡이 끝으로 꿀을 조금 맛보았을 뿐이오나 내가 죽을 수 밖에 없나이다"},{"n":44,"t":"사울이 가로되 요나단아 네가 반드시 죽으리라 그렇지 않으면 하나님이 내게 벌을 내리시고 또 내리시기를 원하노라"},{"n":45,"t":"백성이 사울에게 말하되 이스라엘에 이 큰 구원을 이룬 요나단이 죽겠나이까 결단코 그렇지 아니하니이다 여호와의 사심으로 맹세하옵나니 그의 머리털 하나도 땅에 떨어지지 아니할 것은 그가 오늘 하나님과 동사하였음이니이다 하여 요나단을 구원하여 죽지 않게 하니라"},{"n":46,"t":"사울이 블레셋 사람 따르기를 그치고 올라가매 블레셋 사람이 자기 곳으로 돌아가니라"},{"n":47,"t":"사울이 이스라엘 왕위에 나아간 후에 사방에 있는 모든 대적 곧 모압과 암몬 자손과 에돔과 소바의 왕들과 블레셋 사람을 쳤는데 향하는 곳마다 이기었고"},{"n":48,"t":"용맹 있게 아말렉 사람을 치고 이스라엘을 그 약탈하는 자의 손에서 건졌더라"},{"n":49,"t":"사울의 아들은 요나단과 리스위와 말기수아요 그 두 딸의 이름은 이러하니 맏딸의 이름은 메랍이요 작은 딸의 이름은 미갈이며"},{"n":50,"t":"사울의 아내의 이름은 아히노암이니 아히마아스의 딸이요 그 군장의 이름은 아브넬이니 사울의 숙부 넬의 아들이며"},{"n":51,"t":"사울의 아비는 기스요 아브넬의 아비는 넬이니 아비엘의 아들이었더라"},{"n":52,"t":"사울의 사는 날 동안에 블레셋 사람과 큰 싸움이 있었으므로 사울이 힘있는 자나 용맹있는 자를 보면 그들을 불러 모았더라"}],"kids":[]}},{"chapter":15,"title":"사울이 아말렉을 치다","verses":{"krv":[{"n":1,"t":"사무엘이 사울에게 이르되 여호와께서 나를 보내어 왕에게 기름을 부어 그 백성 이스라엘 위에 왕을 삼으셨은즉 이제 왕은 여호와의 말씀을 들으소서"},{"n":2,"t":"만군의 여호와께서 이같이 말씀하시기를 아말렉이 이스라엘에게 행한 일 곧 애굽에서 나올 때에 길에서 대적한 일을 내가 추억하노니"},{"n":3,"t":"지금 가서 아말렉을 쳐서 그들의 모든 소유를 남기지 말고 진멸하되 남녀와 소아와 젖먹는 아이와 우양과 약대와 나귀를 죽이라 하셨나이다"},{"n":4,"t":"사울이 백성을 소집하고 그들을 들라임에서 계수하니 보병이 이십만이요 유다 사람이 일만이라"},{"n":5,"t":"사울이 아말렉 성에 이르러 골짜기에 복병하니라"},{"n":6,"t":"사울이 겐 사람에게 이르되 아말렉 사람 중에서 떠나 내려가라 그들과 함께 너희를 멸하게 될까 하노라 이스라엘 모든 자손이 애굽에서 올라올 때에 너희가 그들을 선대하였느니라 이에 겐 사람이 아말렉 사람 중에서 떠나니라"},{"n":7,"t":"사울이 하윌라에서부터 애굽 앞 술에 이르기까지 아말렉 사람을 치고"},{"n":8,"t":"아말렉 사람의 왕 아각을 사로잡고 칼날로 그 모든 백성을 진멸하였으되"},{"n":9,"t":"사울과 백성이 아각과 그 양과 소의 가장 좋은 것 또는 기름진 것과 어린 양과 모든 좋은 것을 남기고 진멸키를 즐겨 아니하고 가치 없고 낮은 것은 진멸하니라"},{"n":10,"t":"여호와의 말씀이 사무엘에게 임하니라 가라사대"},{"n":11,"t":"내가 사울을 세워 왕 삼은 것을 후회하노니 그가 돌이켜서 나를 좇지 아니하며 내 명령을 이루지 아니하였음이니라 하신지라 사무엘이 근심하여 온 밤을 여호와께 부르짖으니라"},{"n":12,"t":"사무엘이 사울을 만나려고 아침에 일찍이 일어났더니 혹이 사무엘에게 고하여 가로되 사울이 갈멜에 이르러 자기를 위하여 기념비를 세우고 돌이켜 행하여 길갈로 내려 갔다 하는지라"},{"n":13,"t":"사무엘이 사울에게 이른즉 사울이 그에게 이르되 원컨대 당신은 여호와께 복을 받으소서 내가 여호와의 명령을 행하였나이다"},{"n":14,"t":"사무엘이 가로되 그러면 내 귀에 들어오는 이 양의 소리와 내게 들리는 소의 소리는 어찜이니이까"},{"n":15,"t":"사울이 가로되 그것은 무리가 아말렉 사람에게서 끌어 온 것인데 백성이 당신의 하나님 여호와께 제사하려 하여 양과 소의 가장 좋은 것을 남김이요 그 외의 것은 우리가 진멸하였나이다"},{"n":16,"t":"사무엘이 사울에게 이르되 가만히 계시옵소서 간 밤에 여호와께서 내게 이르신 것을 왕에게 말하리이다 가로되 말씀하소서"},{"n":17,"t":"사무엘이 가로되 왕이 스스로 작게 여길 그 때에 이스라엘 지파의 머리가 되지 아니하셨나이까 여호와께서 왕에게 기름을 부어 이스라엘 왕을 삼으시고"},{"n":18,"t":"또 왕을 길로 보내시며 이르시기를 가서 죄인 아말렉 사람을 진멸하되 다 없어지기까지 치라 하셨거늘"},{"n":19,"t":"어찌하여 왕이 여호와의 목소리를 청종치 아니하고 탈취하기에만 급하여 여호와의 악하게 여기시는 것을 행하였나이까"},{"n":20,"t":"사울이 사무엘에게 이르되 나는 실로 여호와의 목소리를 청종하여 여호와께서 보내신 길로 가서 아말렉 왕 아각을 끌어왔고 아말렉 사람을 진멸하였으나"},{"n":21,"t":"다만 백성이 그 마땅히 멸할 것 중에서 가장 좋은 것으로 길갈에서 당신의 하나님 여호와께 제사하려고 양과 소를 취하였나이다"},{"n":22,"t":"사무엘이 가로되 여호와께서 번제와 다른 제사를 그 목소리 순종하는 것을 좋아하심 같이 좋아하시겠나이까 순종이 제사보다 낫고 듣는 것이 수양의 기름보다 나으니"},{"n":23,"t":"이는 거역하는 것은 사술의 죄와 같고 완고한 것은 사신 우상에게 절하는 죄와 같음이라 왕이 여호와의 말씀을 버렸으므로 여호와께서도 왕을 버려 왕이 되지 못하게 하셨나이다"},{"n":24,"t":"사울이 사무엘에게 이르되 내가 범죄하였나이다 내가 여호와의 명령과 당신의 말씀을 어긴 것은 내가 백성을 두려워하여 그 말을 청종하였음이니이다"},{"n":25,"t":"청하오니 지금 내 죄를 사하고 나와 함께 돌아가서 나로 여호와께 경배하게 하소서"},{"n":26,"t":"사무엘이 사울에게 이르되 나는 왕과 함께 돌아가지 아니하리니 이는 왕이 여호와의 말씀을 버렸으므로 여호와께서 왕을 버려 이스라엘 왕이 되지 못하게 하셨음이니이다 하고"},{"n":27,"t":"사무엘이 가려고 돌이킬 때에 사울이 그의 겉옷자락을 붙잡으매 찢어진지라"},{"n":28,"t":"사무엘이 그에게 이르되 여호와께서 오늘 이스라엘 나라를 왕에게서 떼어서 왕보다 나은 왕의 이웃에게 주셨나이다"},{"n":29,"t":"이스라엘의 지존자는 거짓이나 변개함이 없으시니 그는 사람이 아니시므로 결코 변개치 않으심이니이다"},{"n":30,"t":"사울이 가로되 내가 범죄하였을지라도 청하옵나니 내 백성의 장로들의 앞과 이스라엘의 앞에서 나를 높이사 나와 함께 돌아가서 나로 당신의 하나님 여호와께 경배하게 하소서"},{"n":31,"t":"이에 사무엘이 돌이켜 사울을 따라가매 사울이 여호와께 경배하니라"},{"n":32,"t":"사무엘이 가로되 너희는 아말렉 사람의 왕 아각을 내게로 이끌어 오라 하였더니 아각이 즐거이 오며 가로되 진실로 사망의 괴로움이 지났도다 하니라"},{"n":33,"t":"사무엘이 가로되 네 칼이 여인들로 무자케 한 것 같이 여인 중 네 어미가 무자하리라 하고 그가 길갈에서 여호와 앞에서 아각을 찍어 쪼개니라"},{"n":34,"t":"이에 사무엘은 라마로 가고 사울은 사울 기브아 본집으로 올라가니라"},{"n":35,"t":"사무엘이 죽는 날까지 사울을 다시 가서 보지 아니하였으니 이는 그가 사울을 위하여 슬퍼함이었고 여호와께서는 사울로 이스라엘 왕 삼으신 것을 후회하셨더라"}],"kids":[]}},{"chapter":16,"title":"다윗에게 기름 부음","verses":{"krv":[{"n":1,"t":"여호와께서 사무엘에게 이르시되 내가 이미 사울을 버려 이스라엘 왕이 되지 못하게 하였거늘 네가 그를 위하여 언제까지 슬퍼하겠느냐 너는 기름을 뿔에 채워 가지고 가라 내가 너를 베들레헴 사람 이새에게로 보내리니 이는 내가 그 아들 중에서 한 왕을 예선하였음이니라"},{"n":2,"t":"사무엘이 가로되 내가 어찌 갈 수 있으리이까 사울이 들으면 나를 죽이리이다 여호와께서 가라사대 너는 암송아지를 끌고 가서 말하기를 내가 여호와께 제사를 드리러 왔다 하고"},{"n":3,"t":"이새를 제사에 청하라 내가 너의 행할 일을 가르치리니 내가 네게 알게 하는 자에게 나를 위하여 기름을 부을지니라"},{"n":4,"t":"사무엘이 여호와의 말씀대로 행하여 베들레헴에 이르매 성읍 장로들이 떨며 그를 영접하여 가로되 평강을 위하여 오시나이까"},{"n":5,"t":"가로되 평강을 위함이니라 내가 여호와께 제사하러 왔으니 스스로 성결케 하고 와서 나와 함께 제사하자 하고 이새와 그 아들들을 성결케 하고 제사에 청하니라"},{"n":6,"t":"그들이 오매 사무엘이 엘리압을 보고 마음에 이르기를 여호와의 기름 부으실 자가 과연 그 앞에 있도다 하였더니"},{"n":7,"t":"여호와께서 사무엘에게 이르시되 그 용모와 신장을 보지 말라 내가 이미 그를 버렸노라 나의 보는 것은 사람과 같지 아니하니 사람은 외모를 보거니와 나 여호와는 중심을 보느니라"},{"n":8,"t":"이새가 아비나답을 불러 사무엘의 앞을 지나게 하매 사무엘이 가로되 이도 여호와께서 택하지 아니하셨느니라"},{"n":9,"t":"이새가 삼마로 지나게 하매 사무엘이 가로되 이도 여호와께서 택하지 아니하셨느니라"},{"n":10,"t":"이새가 그 아들 일곱으로 다 사무엘 앞을 지나게 하나 사무엘이 이새에게 이르되 여호와께서 이들을 택하지 아니하셨느니라 하고"},{"n":11,"t":"또 이새에게 이르되 네 아들들이 다 여기 있느냐 이새가 가로되 아직 말째가 남았는데 그가 양을 지키나이다 사무엘이 이새에게 이르되 보내어 그를 데려오라 그가 여기 오기까지는 우리가 식사 자리에 앉지 아니하겠노라"},{"n":12,"t":"이에 보내어 그를 데려오매 그의 빛이 붉고 눈이 빼어나고 얼굴이 아름답더라 여호와께서 가라사대 이가 그니 일어나 기름을 부으라"},{"n":13,"t":"사무엘이 기름 뿔을 취하여 그 형제 중에서 그에게 부었더니 이 날 이후로 다윗이 여호와의 신에게 크게 감동되니라 사무엘이 떠나서 라마로 가니라"},{"n":14,"t":"여호와의 신이 사울에게서 떠나고 여호와의 부리신 악신이 그를 번뇌케 한지라"},{"n":15,"t":"사울의 신하들이 그에게 이르되 보소서 하나님의 부리신 악신이 왕을 번뇌케 하온즉"},{"n":16,"t":"원컨대 우리 주는 주의 앞에 모시는 신하에게 명하여 수금 잘 탈줄 아는 사람을 구하게 하소서 하나님의 부리신 악신이 왕에게 이를 때에 그가 손으로 타면 왕이 나으시리이다"},{"n":17,"t":"사울이 신하에게 이르되 나를 위하여 잘 타는 사람을 구하여 내게로 데려오라"},{"n":18,"t":"소년 중 한사람이 대답하여 가로되 내가 베들레헴 사람 이새의 아들을 본즉 탈줄을 알고 호기와 무용과 구변이 있는 준수한 자라 여호와께서 그와 함께 계시더이다"},{"n":19,"t":"사울이 이에 사자를 이새에게 보내어 이르되 양치는 네 아들 다윗을 내게로 보내라 하매"},{"n":20,"t":"이새가 떡과 한 가죽부대의 포도주와 염소 새끼를 나귀에 실리고 그 아들 다윗의 손으로 사울에게 보내니"},{"n":21,"t":"다윗이 사울에게 이르러 그 앞에 모셔 서매 사울이 그를 크게 사랑하여 자기의 병기 든 자를 삼고"},{"n":22,"t":"이새에게 사람을 보내어 이르되 청컨대 다윗으로 내 앞에 모셔 서게 하라 그가 내게 은총을 얻었느니라 하니라"},{"n":23,"t":"하나님의 부리신 악신이 사울에게 이를 때에 다윗이 수금을 취하여 손으로 탄즉 사울이 상쾌하여 낫고 악신은 그에게서 떠나더라"}],"kids":[]}},{"chapter":17,"title":"다윗과 골리앗","verses":{"krv":[{"n":1,"t":"블레셋 사람들이 그 군대를 모으고 싸우고자 하여 유다에 속한 소고에 모여 소고와 아세가 사이의 에베스담밈에 진치매"},{"n":2,"t":"사울과 이스라엘 사람들이 모여서 엘라 골짜기에 진치고 블레셋 사람을 대하여 항오를 벌였으니"},{"n":3,"t":"블레셋 사람은 이편 산에 섰고 이스라엘은 저편 산에 섰고 사이에는 골짜기가 있었더라"},{"n":4,"t":"블레셋 사람의 진에서 싸움을 돋우는 자가 왔는데 그 이름은 골리앗이요 가드 사람이라 그 신장은 여섯 규빗 한 뼘이요"},{"n":5,"t":"머리에는 놋투구를 썼고 몸에는 어린갑을 입었으니 그 갑옷의 중수가 놋 오천 세겔이며"},{"n":6,"t":"그 다리에는 놋경갑을 쳤고 어깨 사이에는 놋단창을 메었으니"},{"n":7,"t":"그 창자루는 베틀채 같고 창날은 철 육백 세겔이며 방패 든 자는 앞서 행하더라"},{"n":8,"t":"그가 서서 이스라엘 군대를 향하여 외쳐 가로되 너희가 어찌하여 나와서 항오를 벌였느냐 나는 블레셋 사람이 아니며 너희는 사울의 신복이 아니냐 너희는 한 사람을 택하여 내게로 내려보내라"},{"n":9,"t":"그가 능히 싸워서 나를 죽이면 우리가 너희의 종이 되겠고 만일 내가 이기어 그를 죽이면 너희가 우리의 종이 되어 우리를 섬길 것이니라"},{"n":10,"t":"그 블레셋 사람이 또 가로되 내가 오늘날 이스라엘의 군대를 모욕하였으니 사람을 보내어 나로 더불어 싸우게 하라 한지라"},{"n":11,"t":"사울과 온 이스라엘이 블레셋 사람의 이 말을 듣고 놀라 크게 두려워하니라"},{"n":12,"t":"다윗은 유다 베들레헴 에브랏 사람 이새라 하는 자의 아들이었는데 이새는 사울 당시 사람 중에 나이 많아 늙은 자로서 여덟 아들이 있는 중"},{"n":13,"t":"그 장성한 세 아들은 사울을 따라 싸움에 나갔으니 싸움에 나간 세 아들의 이름은 장자 엘리압이요 그 다음은 아비나답이요 제삼은 삼마며"},{"n":14,"t":"다윗은 말째라 장성한 삼 인은 사울을 좇았고"},{"n":15,"t":"다윗은 사울에게로 왕래하며 베들레헴에서 그 아비의 양을 칠 때에"},{"n":16,"t":"그 블레셋 사람이 사십 일을 조석으로 나와서 몸을 나타내었더라"},{"n":17,"t":"이새가 그 아들 다윗에게 이르되 네 형들을 위하여 이 볶은 곡식 한 에바와 이 떡 열 덩이를 가지고 진으로 속히 가서 네 형들에게 주고"},{"n":18,"t":"이 치스 열 덩이를 가져다가 그들의 천부장에게 주고 네 형들의 안부를 살피고 증표를 가져오라"},{"n":19,"t":"때에 사울과 그들과 이스라엘 모든 사람이 엘라 골짜기에서 블레셋 사람과 싸우는 중이더라"},{"n":20,"t":"다윗이 아침에 일찍이 일어나서 양을 양 지키는 자에게 맡기고 이새의 명한 대로 가지고 가서 진영에 이른즉 싸우려고 고함하며"},{"n":21,"t":"이스라엘과 블레섹 사람이 항오를 벌이고 양군이 서로 대하였더라"},{"n":22,"t":"다윗이 그 짐을 짐 지키는 자의 손에 맡기고 군대로 달려가서 형들에게 문안하고"},{"n":23,"t":"그들과 함께 말할 때에 마침 블레셋 사람의 싸움 돋우는 가드 사람 골리앗이라 하는 자가 그 항오에서 나와서 전과 같은 말을 하매 다윗이 들으니라"},{"n":24,"t":"이스라엘 모든 사람이 그 사람을 보고 심히 두려워하여 그 앞에서 도망하며"},{"n":25,"t":"더러는 가로되 너희가 이 올라온 사람을 보았느냐 참으로 이스라엘을 모욕하러 왔도다 그를 죽이는 사람은 왕이 많은 재물로 부하게 하고 그 딸을 그에게 주고 그 아비의 집은 이스라엘 중에서 자유하게 하시리라"},{"n":26,"t":"다윗이 곁에 섰는 사람들에게 말하여 가로되 이 블레셋 사람을 죽여 이스라엘의 치욕을 제하는 사람에게는 어떠한 대우를 하겠느냐 이 할례 없는 블레셋 사람이 누구관대 사시는 하나님의 군대를 모욕하겠느냐"},{"n":27,"t":"백성이 전과 같이 말하여 가로되 그를 죽이는 사람에게는 여차 여차히 하시리라 하니라"},{"n":28,"t":"장형 엘리압이 다윗이 사람들에게 하는 말을 들은지라 그가 다윗에게 노를 발하여 가로되 네가 어찌하여 이리로 내려왔느냐 들에 있는 몇 양을 뉘게 맡겼느냐 나는 네 교만과 네 마음의 완악함을 아노니 네가 전쟁을 구경하러 왔도다"},{"n":29,"t":"다윗이 가로되 내가 무엇을 하였나이까 어찌 이유가 없으리이까 하고"},{"n":30,"t":"돌이켜 다른 사람을 향하여 전과 같이 말하매 백성이 전과 같이 대답하니라"},{"n":31,"t":"혹이 다윗의 한 말을 듣고 그것을 사울에게 고하였으므로 사울이 다윗을 부른지라"},{"n":32,"t":"다윗이 사울에게 고하되 그를 인하여 사람이 낙담하지 말 것이라 주의 종이 가서 저 블레셋 사람과 싸우리이다"},{"n":33,"t":"사울이 다윗에게 이르되 네가 가서 저 블레셋 사람과 싸우기에 능치 못하리니 너는 소년이요 그는 어려서부터 용사임이니라"},{"n":34,"t":"다윗이 사울에게 고하되 주의 종이 아비의 양을 지킬 때에 사자나 곰이 와서 양떼에서 새끼를 움키면"},{"n":35,"t":"내가 따라가서 그것을 치고 그 입에서 새끼를 건져 내었고 그것이 일어나 나를 해하고자 하면 내가 그 수염을 잡고 그것을 쳐 죽였었나이다"},{"n":36,"t":"주의 종이 사자와 곰도 쳤은즉 사시는 하나님의 군대를 모욕한 이 할례 없는 블레셋 사람이리이까 그가 그 짐승의 하나와 같이 되리이다"},{"n":37,"t":"또 가로되 여호와께서 나를 사자의 발톱과 곰의 발톱에서 건져 내셨은즉 나를 이 블레셋 사람의 손에서도 건져 내시리이다 사울이 다윗에게 이르되 가라 여호와께서 너와 함께 계시기를 원하노라"},{"n":38,"t":"이에 사울이 자기 군복을 다윗에게 입히고 놋투구를 그 머리에 씌우고 또 그에게 갑옷을 입히매"},{"n":39,"t":"다윗이 칼을 군복 위에 차고는 익숙치 못하므로 시험적으로 걸어 보다가 사울에게 고하되 익숙치 못하니 이것을 입고 가지 못하겠나이다 하고 곧 벗고"},{"n":40,"t":"손에 막대기를 가지고 시내에서 매끄러운 돌 다섯을 골라서 자기 목자의 제구 곧 주머니에 넣고 손에 물매를 가지고 블레셋 사람에게로 나아가니라"},{"n":41,"t":"블레셋 사람이 점점 행하여 다윗에게로 나아오는데 방패 든 자가 앞섰더라"},{"n":42,"t":"그 블레셋 사람이 둘러보다가 다윗을 보고 업신여기니 이는 그가 젊고 붉고 용모가 아름다움이라"},{"n":43,"t":"블레셋 사람이 다윗에게 이르되 네가 나를 개로 여기고 막대기를 가지고 내게 나아왔느냐 하고 그 신들의 이름으로 다윗을 저주하고"},{"n":44,"t":"또 이르되 내게로 오라 내가 네 고기를 공중의 새들과 들짐승들에게 주리라"},{"n":45,"t":"다윗이 블레셋 사람에게 이르되 너는 칼과 창과 단창으로 내게 오거니와 나는 만군의 여호와의 이름 곧 네가 모욕하는 이스라엘 군대의 하나님의 이름으로 네게 가노라"},{"n":46,"t":"오늘 여호와께서 너를 내 손에 붙이시리니 내가 너를 쳐서 네 머리를 베고 블레셋 군대의 시체로 오늘날 공중의 새와 땅의 들짐승에게 주어 온 땅으로 이스라엘에 하나님이 계신줄 알게 하겠고"},{"n":47,"t":"또 여호와의 구원하심이 칼과 창에 있지 아니함을 이 무리로 알게 하리라 전쟁은 여호와께 속한 것인즉 그가 너희를 우리 손에 붙이시리라"},{"n":48,"t":"블레셋 사람이 일어나 다윗에게로 마주 가까이 올 때에 다윗이 블레셋 사람에게로 마주 그 항오를 향하여 빨리 달리며"},{"n":49,"t":"손을 주머니에 넣어 돌을 취하여 물매로 던져 블레셋 사람의 이마를 치매 돌이 그 이마에 박히니 땅에 엎드러지니라"},{"n":50,"t":"다윗이 이같이 물매와 돌로 블레셋 사람을 이기고 그를 쳐 죽였으나 자기 손에는 칼이 없었더라"},{"n":51,"t":"다윗이 달려가서 블레셋 사람을 밟고 그의 칼을 그 집에서 빼어 내어 그 칼로 그를 죽이고 그 머리를 베니 블레셋 사람들이 자기 용사의 죽음을 보고 도망하는지라"},{"n":52,"t":"이스라엘과 유다 사람들이 일어나서 소리지르며 블레셋 사람을 쫓아 가이와 에그론 성문까지 이르렀고 블레셋 사람의 상한 자들은 사아라임 가는 길에서부터 가드와 에그론까지 엎드러졌더라"},{"n":53,"t":"이스라엘 자손이 블레셋 사람을 쫓다가 돌아와서 그들의 진을 노략하였고"},{"n":54,"t":"다윗은 블레셋 사람의 머리를 예루살렘으로 가져가고 갑주는 자기 장막에 두니라"},{"n":55,"t":"다윗이 블레셋 사람을 향하여 나감을 사울이 보고 군장 아브넬에게 묻되 아브넬아 이 소년이 뉘 아들이냐 아브넬이 가로되 왕이여 왕의 사심으로 맹세하옵나니 내가 알지 못하나이다 하매"},{"n":56,"t":"왕이 가로되 너는 이 청년이 누구의 아들인가 물어보라 하였더니"},{"n":57,"t":"다윗이 블레셋 사람을 죽이고 돌아올 때에 블레셋 사람의 머리가 그 손에 있는 채 아브넬이 그를 사울의 앞으로 인도하니"},{"n":58,"t":"사울이 그에게 묻되 소년이여 누구의 아들이뇨 다윗이 대답하되 나는 주의 종 베들레헴 사람 이새의 아들이니이다"}],"kids":[]}},{"chapter":18,"title":"사울이 다윗을 시기함","verses":{"krv":[{"n":1,"t":"다윗이 사울에게 말하기를 마치매 요나단의 마음이 다윗의 마음과 연락되어 요나단이 그를 자기 생명 같이 사랑하니라"},{"n":2,"t":"그 날에 사울은 다윗을 머무르게 하고 그 아비의 집으로 다시 돌아가기를 허락지 아니하였고"},{"n":3,"t":"요나단은 다윗을 자기 생명 같이 사랑하여 더불어 언약을 맺었으며"},{"n":4,"t":"요나단이 자기의 입었던 겉옷을 벗어 다윗에게 주었고 그 군복과 칼과 활과 띠도 그리하였더라"},{"n":5,"t":"다윗이 사울의 보내는 곳마다 가서 지혜롭게 행하매 사울이 그로 군대의 장을 삼았더니 온 백성이 합당히 여겼고 사울의 신하들도 합당히 여겼더라"},{"n":6,"t":"무리가 돌아올 때 곧 다윗이 블레셋 사람을 죽이고 돌아올 때에 여인들이 이스라엘 모든 성에서 나와서 노래하며 춤추며 소고와 경쇠를 가지고 왕 사울을 환영하는데"},{"n":7,"t":"여인들이 뛰놀며 창화하여 가로되 사울의 죽인 자는 천천이요 다윗은 만만이로다 한지라"},{"n":8,"t":"사울이 이 말에 불쾌하여 심히 노하여 가로되 다윗에게는 만만을 돌리고 내게는 천천만 돌리니 그의 더 얻을 것이 나라 밖에 무엇이냐 하고"},{"n":9,"t":"그 날 후로 사울이 다윗을 주목하였더라"},{"n":10,"t":"그 이튿날 하나님의 부리신 악신이 사울에게 힘있게 내리매 그가 집 가운데서 야료하는고로 다윗이 평일과 같이 손으로 수금을 타는데 때에 사울의 손에 창이 있는지라"},{"n":11,"t":"그가 스스로 이르기를 내가 다윗을 벽에 박으리라 하고 그 창을 던졌으나 다윗이 그 앞에서 두 번 피하였더라"},{"n":12,"t":"여호와께서 사울을 떠나 다윗과 함께 계시므로 사울이 그를 두려워한지라"},{"n":13,"t":"그러므로 사울이 그로 자기를 떠나게 하고 천부장을 삼으매 그가 백성 앞에 출입하며"},{"n":14,"t":"그 모든 일을 지혜롭게 행하니라 여호와께서 그와 함께 계시니라"},{"n":15,"t":"사울이 다윗의 크게 지혜롭게 행함을 보고 그를 두려워하였으나"},{"n":16,"t":"온 이스라엘과 유다는 다윗을 사랑하였으니 그가 자기들 앞에 출입함을 인함이었더라"},{"n":17,"t":"사울이 다윗에게 이르되 내 맏딸 메랍을 네게 아내로 주리니 오직 너는 나를 위하여 용맹을 내어 여호와의 싸움을 싸우라 하니 이는 그가 생각하기를 내 손을 그에게 대지 말고 블레셋 사람의 손으로 그에게 대게 하리라 함이라"},{"n":18,"t":"다윗이 사울에게 이르되 내가 누구며 이스라엘 중에 내 친속이나 내 아비의 집이 무엇이관대 내가 왕의 사위가 되리이까 하였더니"},{"n":19,"t":"사울의 딸 메랍을 다윗에게 줄 시기에 므홀랏 사람 아드리엘에게 아내로 준바 되었더라"},{"n":20,"t":"사울의 딸 미갈이 다윗을 사랑하매 혹이 사울에게 고한지라 사울이 그 일을 좋게 여겨"},{"n":21,"t":"스스로 이르되 내가 딸을 그에게 주어서 그에게 올무가 되게 하고 블레셋 사람의 손으로 그를 치게 하리라 하고 이에 다윗에게 이르되 네가 오늘 다시 내 사위가 되리라 하니라"},{"n":22,"t":"사울이 그 신하들에게 명하되 너희는 다윗에게 비밀히 말하여 이르기를 보라 왕이 너를 기뻐하시고 모든 신하도 너를 사랑하나니 그런즉 네가 왕의 사위가 되는 것이 가하니라 하라"},{"n":23,"t":"사울의 신하들이 이 말로 다윗의 귀에 고하매 다윗이 가로되 왕의 사위 되는 것을 너희는 경한 일로 보느냐 나는 가난하고 천한 사람이로라 한지라"},{"n":24,"t":"사울의 신하들이 사울에게 고하여 가로되 다윗이 여차여차히 말하더이다"},{"n":25,"t":"사울이 가로되 너희는 다윗에게 이같이 말하기를 왕이 아무 폐백도 원치 아니하고 다만 왕의 원수의 보족으로 블레셋 사람의 양피 일백을 원하신다 하라 하였으니 이는 사울의 생각에 다윗을 블레셋 사람의 손에 죽게 하리라 함이라"},{"n":26,"t":"사울의 신하들이 이 말로 다윗에게 고하매 다윗이 왕의 사위 되는 것을 좋게 여기므로 만기가 되지 못하여서"},{"n":27,"t":"다윗이 일어나서 그 종자와 함께 가서 블레셋 사람 이백 명을 죽이고 그 양피를 가져다가 수대로 왕께 드려 왕의 사위가 되고자 하니 사울이 그 딸 미갈을 다윗에게 아내로 주었더라"},{"n":28,"t":"여호와께서 다윗과 함께 계심을 사울이 보고 알았고 사울의 딸 미갈도 그를 사랑하므로"},{"n":29,"t":"사울이 다윗을 더욱 더욱 두려워하여 평생에 다윗의 대적이 되니라"},{"n":30,"t":"블레셋 사람의 방백들이 나오면 그들의 나올 때마다 다윗이 사울의 모든 신하보다 더 지혜롭게 행하매 이에 그 이름이 심히 귀중히 되니라"}],"kids":[]}},{"chapter":19,"title":"다윗이 도망감","verses":{"krv":[{"n":1,"t":"사울이 그 아들 요나단과 그 모든 신하에게 다윗을 죽이라 말하였더니 사울의 아들 요나단이 다윗을 심히 기뻐하므로"},{"n":2,"t":"그가 다윗에게 고하여 가로되 내 부친 사울이 너를 죽이기를 꾀하시느니라 그러므로 이제 청하노니 아침에 조심하여 은밀한 곳에 숨어 있으라"},{"n":3,"t":"내가 나가서 너 있는 들에서 내 부친 곁에 서서 네 일을 내 부친과 말하다가 무엇을 보거든 네게 알게 하리라 하고"},{"n":4,"t":"요나단이 그 아비 사울에게 다윗을 포장하여 가로되 원컨대 왕은 신하 다윗에게 범죄치 마옵소서 그는 왕께 득죄하지 아니하였고 그가 왕께 행한 일은 심히 선함이니이다"},{"n":5,"t":"그가 자기 생명을 아끼지 아니하고 블레셋 사람을 죽였고 여호와께서는 온 이스라엘을 위하여 큰 구원을 이루셨으므로 왕이 이를 보고 기뻐하셨거늘 어찌 무고히 다윗을 죽여 무죄한 피를 흘려 범죄하려 하시나이까"},{"n":6,"t":"사울이 요나단의 말을 듣고 맹세하되 여호와께서 사시거니와 그가 죽임을 당치 아니하리라"},{"n":7,"t":"요나단이 다윗을 불러 그 모든 일을 알게 하고 그를 사울에게로 인도하니 그가 사울 앞에 여전히 있으니라"},{"n":8,"t":"전쟁이 다시 있으므로 다윗이 나가서 블레셋 사람들과 싸워 그들을 크게 도륙하매 그들이 그 앞에서 도망하니라"},{"n":9,"t":"사울이 손에 단창을 가지고 그 집에 앉았을 때에 여호와의 부리신 악신이 사울에게 접하였으므로 다윗이 손으로 수금을 탈 때에"},{"n":10,"t":"사울이 단창으로 다윗을 벽에 박으려 하였으나 그는 사울의 앞을 피하고 사울의 창은 벽에 박힌지라 다윗이 그 밤에 도피하매"},{"n":11,"t":"사울이 사자들을 다윗의 집에 보내어 그를 지키다가 아침에 그를 죽이게 하려 한지라 다윗의 아내 미갈이 다윗에게 일러 가로되 당신이 이 밤에 당신의 생명을 구하지 아니하면 내일에는 죽임을 당하리라 하고"},{"n":12,"t":"미갈이 다윗을 창에서 달아 내리우매 그가 도망하여 피하니라"},{"n":13,"t":"미갈이 우상을 취하여 침상에 뉘고 염소털로 엮은 것을 그 머리에 씌우고 의복으로 그것을 덮었더니"},{"n":14,"t":"사울이 사자들을 보내어 다윗을 잡으려 하매 미갈이 가로되 그가 병들었느니라"},{"n":15,"t":"사울이 또 사자들을 보내어 다윗을 보라 하며 이르되 그를 침상채 내게로 가져오라 내가 그를 죽이리라"},{"n":16,"t":"사자들이 들어가 본즉 침상에 우상이 있고 염소털로 엮은 것이 그 머리에 있었더라"},{"n":17,"t":"사울이 미갈에게 이르되 너는 어찌하여 이처럼 나를 속여 내 대적을 놓아 피하게 하였느냐 미갈이 사울에게 대답하되 그가 내게 이르기를 나를 놓아 가게 하라 어찌하여 나로 너를 죽이게 하겠느냐 하더이다 하니라"},{"n":18,"t":"다윗이 도피하여 라마로 가서 사무엘에게로 나아가서 사울이 자기에게 행한 일을 다 고하였고 다윗과 사무엘이 나욧으로 가서 거하였더라"},{"n":19,"t":"혹이 사울에게 고하여 가로되 다윗이 라마 나욧에 있더이다 하매"},{"n":20,"t":"사울이 다윗을 잡으려 사자들을 보내었더니 그들이 선지자 무리의 예언하는 것과 사무엘이 그들의 수령으로 선 것을 볼 때에 하나님의 신이 사울의 사자들에게 임하매 그들도 예언을 한지라"},{"n":21,"t":"혹이 그것을 사울에게 고하매 사울이 다른 사자들을 보내었더니 그들도 예언을 한고로 사울이 세번째 다시 사자들을 보내었더니 그들도 예언을 한지라"},{"n":22,"t":"이에 사울도 라마로 가서 세구에 있는 큰 우물에 이르러 물어 가로되 사무엘과 다윗이 어디 있느냐 혹이 가로되 라마 나욧에 있나이다"},{"n":23,"t":"사울이 라마 나욧으로 가니라 하나님의 신이 그에게도 임하시니 그가 라마 나욧에 이르기까지 행하며 예언을 하였으며"},{"n":24,"t":"그가 또 그 옷을 벗고 사무엘 앞에서 예언을 하며 종일 종야에 벌거벗은 몸으로 누웠었더라 그러므로 속담에 이르기를 사울도 선지자 중에 있느냐 하니라"}],"kids":[]}},{"chapter":20,"title":"요나단과 다윗의 우정","verses":{"krv":[{"n":1,"t":"다윗이 라마 나욧에서 도망하여 와서 요나단에게 이르되 내가 무엇을 하였으며 내 죄악이 무엇이며 네 부친 앞에서 나의 죄가 무엇이관대 그가 내 생명을 찾느뇨"},{"n":2,"t":"요나단이 그에게 이르되 결단코 아니라 네가 죽지 아니하리라 내 부친이 대소사를 내게 알게 아니하고는 행함이 없나니 내 부친이 어찌하여 이 일은 내게 숨기리요 그렇지 아니하니라"},{"n":3,"t":"다윗이 또 맹세하여 가로되 내가 네게 은혜 받은 줄을 네 부친이 밝히 알고 스스로 이르기를 요나단이 슬퍼할까 두려운즉 그로 이를 알게 하지 아니하리라 함이니라 그러나 진실로 여호와의 사심과 네 생명으로 맹세하노니 나와 사망의 사이는 한 걸음뿐이니라"},{"n":4,"t":"요나단이 다윗에게 이르되 네 마음의 소원이 무엇이든지 내가 너를 위하여 그것을 이루리라"},{"n":5,"t":"다윗이 요나단에게 이르되 내일은 월삭인즉 내가 마땅히 왕을 모시고 앉아 식사를 하여야 할 것이나 나를 보내어 제삼일 저녁까지 들에 숨게 하고"},{"n":6,"t":"네 부친이 만일 나를 자세히 묻거든 그 때에 너는 말하기를 다윗이 자기 성 베들레헴으로 급히 가기를 내게 허하라 간청하였사오니 이는 온 가족을 위하여 거기서 매년제를 드릴 때가 됨이니이다 하라"},{"n":7,"t":"그의 말이 좋다 하면 네 종이 평안하려니와 그가 만일 노하면 나를 해하려고 결심한 줄을 알지니"},{"n":8,"t":"그런즉 원컨대 네 종에게 인자히 행하라 네가 네 종으로 여호와 앞에서 너와 맹약케 하였음이니라 그러나 내게 죄악이 있거든 네가 친히 나를 죽이라 나를 네 부친에게로 데려갈 것이 무엇이뇨"},{"n":9,"t":"요나단이 가로되 이 일이 결코 네게 있지 아니하리라 내 부친이 너를 해하려 결심한줄 알면 내가 네게 이르지 아니하겠느냐"},{"n":10,"t":"다윗이 요나단에게 이르되 네 부친이 혹 엄하게 네게 대답하면 누가 그것을 내게 고하겠느냐"},{"n":11,"t":"요나단이 다윗에게 이르되 오라 우리가 들로 가자 하고 두 사람이 들로 가니라"},{"n":12,"t":"요나단이 다윗에게 이르되 이스라엘의 하나님 여호와께서 증거하시거니와 내가 내일이나 모레 이맘 때에 내 부친을 살펴서 너 다윗에게 대한 의향이 선하면 내가 보내어 네게 알게 하지 않겠느냐"},{"n":13,"t":"그러나 만일 내 부친이 너를 해하려 하거늘 내가 이 일을 네게 알게 하여 너를 보내어 평안히 가게 하지 아니하면 여호와께서 나 요나단에게 벌을 내리시고 또 내리시기를 원하노라 여호와께서 내 부친과 함께 하신 것 같이 너와 함께 하시기를 원하노니"},{"n":14,"t":"너는 나의 사는 날 동안에 여호와의 인자를 내게 베풀어서 나로 죽지 않게 할 뿐 아니라"},{"n":15,"t":"여호와께서 너 다윗의 대적들을 지면에서 다 끊어버리신 때에도 너는 네 인자를 내 집에서 영영히 끊어 버리지 말라 하고"},{"n":16,"t":"이에 요나단이 다윗의 집과 언약하기를 여호와께서는 다윗의 대적들을 치실지어다 하니라"},{"n":17,"t":"요나단이 다윗을 사랑하므로 그로 다시 맹세케 하였으니 이는 자기 생명을 사랑함 같이 그를 사랑함이었더라"},{"n":18,"t":"요나단이 다윗에게 이르되 내일은 월삭인즉 네 자리가 비므로 네가 없음을 자세히 물으실 것이라"},{"n":19,"t":"너는 사흘을 있다가 빨리 내려가서 그 일이 있던 날에 숨었던 곳에 이르러 에셀 바위 곁에 있으라"},{"n":20,"t":"내가 과녁을 쏘려 함 같이 살 셋을 그 곁에 쏘고"},{"n":21,"t":"아이를 보내어 가서 살을 찾으라 하며 내가 짐짓 아이에게 이르기를 보라 살이 네 이편에 있으니 가져오라 하거든 너는 돌아올지니 여호와께서 사시거니와 네가 평안 무사할 것이요"},{"n":22,"t":"만일 아이에게 이르기를 보라 살이 네 앞편에 있다 하거든 네 길을 가라 여호와께서 너를 보내셨음이니라"},{"n":23,"t":"너와 내가 말한 일에 대하여는 여호와께서 너와 나 사이에 영영토록 계시느니라"},{"n":24,"t":"다윗이 들에 숨으니라 월삭이 되매 왕이 앉아 음식을 먹을 때에"},{"n":25,"t":"왕은 평시와 같이 벽 곁 자기 자리에 앉았고 요나단은 섰고 아브넬은 사울의 곁에 앉았고 다윗의 자리는 비었으나"},{"n":26,"t":"그러나 그 날에는 사울이 아무 말도 아니하였으니 이는 생각하기를 그에게 무슨 사고가 있어서 부정한가보다 정녕히 부정한가보다 하였음이더니"},{"n":27,"t":"이튿날 곧 달의 제이일에도 다윗의 자리가 오히려 비었으므로 사울이 그 아들 요나단에게 묻되 이새의 아들이 어찌하여 어제와 오늘 식사에 나오지 아니하느뇨"},{"n":28,"t":"요나단이 사울에게 대답하되 다윗이 내게 베들레헴으로 가기를 간청하여"},{"n":29,"t":"가로되 청컨대 나로 가게 하라 우리 가족이 그 성에서 제사할 일이 있으므로 나의 형이 내게 오기를 명하였으니 내가 네게 사랑을 받거든 나로 가서 내 형들을 보게 하라 하였으므로 그가 왕의 식사 자리에 오지 아니하였나이다"},{"n":30,"t":"사울이 요나단에게 노를 발하고 그에게 이르되 패역부도의 계집의 소생아 네가 이새의 아들을 택한 것이 네 수치와 네 어미의 벌거벗은 수치됨을 내가 어찌 알지 못하랴"},{"n":31,"t":"이새의 아들이 땅에 사는 동안은 너와 네 나라가 든든히 서지 못하리라 그런즉 이제 보내어 그를 내게로 끌어오라 그는 죽어야 할 자니라"},{"n":32,"t":"요나단이 그 부친 사울에게 대답하여 가로되 그가 죽을 일이 무엇이니이까 무엇을 행하였나이까"},{"n":33,"t":"사울이 요나단에게 단창을 던져 치려 한지라 요나단이 그 부친이 다윗을 죽이기로 결심한줄 알고"},{"n":34,"t":"심히 노하여 식사 자리에서 떠나고 달의 제이일에는 먹지 아니하였으니 이는 그 부친이 다윗을 욕되게 하였으므로 다윗을 위하여 슬퍼함이었더라"},{"n":35,"t":"아침에 요나단이 작은 아이를 데리고 다윗과 정한 시간에 들로 나가서"},{"n":36,"t":"아이에게 이르되 달려가서 나의 쏘는 살을 찾으라 하고 아이가 달려갈 때에 요나단이 살을 그의 위로 지나치게 쏘니라"},{"n":37,"t":"아이가 요나단의 쏜 살 있는 곳에 이를 즈음에 요나단이 아이 뒤에서 외쳐 가로되 살이 네 앞편에 있지 아니하냐 하고"},{"n":38,"t":"요나단이 아이 뒤에서 또 외치되 지체 말고 빨리 달음질하라 하매 요나단의 아이가 살을 주워 가지고 주인에게로 돌아왔으나"},{"n":39,"t":"그 아이는 아무런지 알지 못하고 요나단과 다윗만 그 일을 알았더라"},{"n":40,"t":"요나단이 그 병기를 아이에게 주며 이르되 이것을 가지고 성으로 가라"},{"n":41,"t":"아이가 가매 다윗이 곧 바위 남편에서 일어나서 땅에 엎드려 세 번 절한 후에 피차 입맞추고 같이 울되 다윗이 더욱 심하더니"},{"n":42,"t":"요나단이 다윗에게 이르되 평안히 가라 우리 두 사람이 여호와의 이름으로 맹세하여 이르기를 여호와께서 영원히 나와 너 사이에 계시고 내 자손과 네 자손 사이에 계시리라 하였느니라 다윗은 일어나 떠나고 요나단은 성으로 들어오니라"}],"kids":[]}},{"chapter":21,"title":"놉의 떡과 가드로 도망","verses":{"krv":[{"n":1,"t":"다윗이 놉에 가서 제사장 아히멜렉에게 이르니 아히멜렉이 떨며 다윗을 영접하며 그에게 이르되 어찌하여 네가 홀로 있고 함께 하는 자가 아무도 없느냐"},{"n":2,"t":"다윗이 제사장 아히멜렉에게 이르되 왕이 내게 일을 명하고 이르시기를 내가 너를 보내는 바와 네게 명한 바 일의 아무 것이라도 사람에게 알게 하지 말라 하시기로 내가 나의 소년들을 여차여차한 곳으로 약정하였나이다"},{"n":3,"t":"이제 당신의 수중에 무엇이 있나이까 떡 다섯 덩이나 무엇이든지 있는 대로 내 손에 주소서"},{"n":4,"t":"제사장이 다윗에게 대답하여 가로되 항용 떡은 내 수중에 없으나 거룩한 떡은 있나니 그 소년들이 부녀를 가까이만 아니하였으면 주리라"},{"n":5,"t":"다윗이 제사장에게 대답하여 가로되 우리가 참으로 삼 일 동안이나 부녀를 가까이 하지 아니하였나이다 나의 떠난 길이 보통 여행이라도 소년들의 그릇이 성결하겠거든 하물며 오늘날 그들의 그릇이 성결치 아니하겠나이까 하매"},{"n":6,"t":"제사장이 그 거룩한 떡을 주었으니 거기는 진설병 곧 여호와 앞에서 물려 낸 떡밖에 없음이라 이 떡은 더운 떡을 드리는 날에 물려낸 것이더라"},{"n":7,"t":"그 날에 사울의 신하 한 사람이 여호와 앞에 머물러 있었는데 그는 도엑이라 이름하는 에돔 사람이요 사울의 목자장이었더라"},{"n":8,"t":"다윗이 아히멜렉에게 이르되 여기 당신의 수중에 창이나 칼이 없나이까 왕의 일이 급하므로 내가 내 칼과 병기를 가지지 못하였나이다"},{"n":9,"t":"제사장이 가로되 네가 엘라 골짜기에서 죽인 블레셋 사람 골리앗의 칼이 보자기에 싸여 에봇 뒤에 있으니 네가 그것을 가지려거든 가지라 여기는 그 밖에 다른 것이 없느니라 다윗이 가로되 그같은 것이 또 없나니 내게 주소서"},{"n":10,"t":"그 날에 다윗이 사울을 두려워하여 일어나 도망하여 가드 왕 아기스에게로 가니"},{"n":11,"t":"아기스의 신하들이 아기스에게 고하되 이는 그 땅의 왕 다윗이 아니니이까 무리가 춤추며 이 사람의 일을 창화하여 가로되 사울의 죽인 자는 천천이요 다윗은 만만이로다 하지 아니하였나이까 한지라"},{"n":12,"t":"다윗이 이 말을 그 마음에 두고 가드 왕 아기스를 심히 두려워하여"},{"n":13,"t":"그들의 앞에서 그 행동을 변하여 미친 체 하고 대문짝에 그적거리며 침을 수염에 흘리매"},{"n":14,"t":"아기스가 그 신하에게 이르되 너희도 보거니와 이 사람이 미치광이로다 어찌하여 그를 내게로 데려왔느냐"},{"n":15,"t":"내게 미치광이가 부족하여서 너희가 이 자를 데려다가 내 앞에서 미친 짓을 하게 하느냐 이 자가 어찌 내 집에 들어오겠느냐 하니라"}],"kids":[]}},{"chapter":22,"title":"아둘람과 놉 제사장의 학살","verses":{"krv":[{"n":1,"t":"그러므로 다윗이 그곳을 떠나 아둘람 굴로 도망하매 그 형제와 아비의 온 집이 듣고는 그리로 내려가서 그에게 이르렀고"},{"n":2,"t":"환난 당한 모든 자와 빚진 자와 마음이 원통한 자가 다 그에게로 모였고 그는 그 장관이 되었는데 그와 함께 한 자가 사백 명 가량이었더라"},{"n":3,"t":"다윗이 거기서 모압 미스베로 가서 모압 왕에게 이르되 하나님이 나를 위하여 어떻게 하실 것을 내가 알기까지 나의 부모로 나와서 당신들과 함께 있게 하기를 청하나이다 하고"},{"n":4,"t":"부모를 인도하여 모압 왕 앞에 나아갔더니 그들이 다윗의 요새에 있을 동안에 모압 왕과 함께 있었더라"},{"n":5,"t":"선지자 갓이 다윗에게 이르되 이 요새에 있지 말고 떠나 유다땅으로 들어가라 다윗이 떠나 헤렛 수풀에 이르니라"},{"n":6,"t":"사울이 다윗과 그와 함께 있는 사람들이 나타났다 함을 들으니라 때에 사울이 기브아 높은 곳에서 손에 단창을 들고 에셀나무 아래 앉았고 모든 신하들은 그 곁에 섰더니"},{"n":7,"t":"사울이 곁에 선 신하들에게 이르되 너희 베냐민 사람들아 들으라 이새의 아들이 너희에게 각기 밭과 포도원을 주며 너희로 천부장, 백부장을 삼겠느냐"},{"n":8,"t":"너희가 다 공모하여 나를 대적하며 내 아들이 이새의 아들과 맹약하였으되 내게 고발하는 자가 하나도 없고 나를 위하여 슬퍼하거나 내 아들이 내 신하를 선동하여 오늘이라도 매복하였다가 나를 치려 하는 것을 내게 고발하는 자가 하나도 없도다"},{"n":9,"t":"때에 에돔 사람 도엑이 사울의 신하 중에 섰더니 대답하여 가로되 이새의 아들이 놉에 와서 아히둡의 아들 아히멜렉에게 이른 것을 내가 보았었는데"},{"n":10,"t":"아히멜렉이 그를 위하여 여호와께 묻고 그에게 식물도 주고 블레셋 사람 골리앗의 칼도 주더이다"},{"n":11,"t":"왕이 보내어 아히둡의 아들 제사장 아히멜렉과 그 아비의 온 집 곧 놉에 있는 제사장들을 부르매 그들이 다 왕께 이른지라"},{"n":12,"t":"사울이 가로되 너 아히둡의 아들아 들으라 대답하되 내 주여 내가 여기 있나이다"},{"n":13,"t":"사울이 그에게 이르되 네가 어찌하여 이새의 아들과 공모하여 나를 대적하여 그에게 떡과 칼을 주고 그를 위하여 하나님께 물어서 그로 오늘이라도 매복하였다가 나를 치게 하려 하였느뇨"},{"n":14,"t":"아히멜렉이 왕에게 대답하여 가로되 왕의 모든 신하 중에 다윗 같이 충실한 자가 누구인지요 그는 왕의 사위도 되고 왕의 모신도 되고 왕실에서 존귀한 자가 아니니이까"},{"n":15,"t":"내가 그를 위하여 하나님께 물은 것이 오늘이 처음이니이까 결단코 아니니이다 원컨대 왕은 종과 종의 아비의 온 집에 아무 것도 돌리지 마옵소서 왕의 종은 이 모든 일의 대소간에 아는 것이 없나이다"},{"n":16,"t":"왕이 가로되 아히멜렉아 네가 반드시 죽을 것이요 네 아비의 온 집도 그러하리라 하고"},{"n":17,"t":"왕이 좌우의 시위자에게 이르되 돌이켜 가서 여호와의 제사장들을 죽이라 그들도 다윗과 합력하였고 또 그들이 다윗의 도망한 것을 알고도 내게 고발치 아니하였음이니라 하나 왕의 신하들이 손을 들어 여호와의 제사장들 죽이기를 싫어한지라"},{"n":18,"t":"왕이 도엑에게 이르되 너는 돌이켜 제사장들을 죽이라 하매 에돔 사람 도엑이 돌이켜 제사장들을 쳐서 그 날에 세마포 에봇 입은 자 팔십오 인을 죽였고"},{"n":19,"t":"제사장들의 성읍 놉의 남녀와 아이들과 젖먹는 자들과 소와 나귀와 양을 칼로 쳤더라"},{"n":20,"t":"아히둡의 아들 아히멜렉의 아들 중 하나가 피하였으니 그 이름은 아비아달이라 그가 도망하여 다윗에게로 가서"},{"n":21,"t":"사울이 여호와의 제사장들 죽인 일을 다윗에게 고하매"},{"n":22,"t":"다윗이 아비아달에게 이르되 그 날에 에돔 사람 도엑이 거기 있기로 그가 반드시 사울에게 고할 줄 내가 알았노라 네 아비 집의 모든 사람 죽은 것이 나의 연고로다"},{"n":23,"t":"두려워 말고 내게 있으라 내 생명을 찾는 자가 네 생명도 찾는 자니 네가 나와 함께 있으면 보전하리라 하니라"}],"kids":[]}},{"chapter":23,"title":"그일라와 십 광야의 도피","verses":{"krv":[{"n":1,"t":"혹이 다윗에게 고하여 가로되 보소서 블레셋 사람이 그일라를 쳐서 그 타작 마당을 탈취하더이다"},{"n":2,"t":"이에 다윗이 여호와께 묻자와 가로되 내가 가서 이 블레셋 사람을 치리이까 여호와께서 다윗에게 이르시되 가서 블레셋 사람을 치고 그일라를 구원하라 하시니"},{"n":3,"t":"다윗의 사람들이 그에게 이르되 보소서 우리가 유다에 있기도 두렵거든 하물며 그일라에 가서 블레셋 사람의 군대를 치는 일이리이까"},{"n":4,"t":"다윗이 여호와께 다시 묻자온대 여호와께서 대답하여 가라사대 일어나 그일라로 내려가라 내가 블렛셋 사람을 네 손에 붙이리라 하신지라"},{"n":5,"t":"다윗과 그의 사람들이 그일라로 가서 블레셋 사람과 싸워 그들을 크게 도륙하고 그들의 가축을 끌어오니라 다윗이 이와 같이 그일라 거민을 구원하니라"},{"n":6,"t":"아히멜렉의 아들 아비아달이 그일라 다윗에게로 도망할 때에 손에 에봇을 가지고 내려왔었더라"},{"n":7,"t":"다윗이 그일라에 온 것을 혹이 사울에게 고하매 사울이 가로되 하나님이 그를 내 손에 붙이셨도다 그가 문과 문빗장이 있는 성에 들어갔으니 갇혔도다"},{"n":8,"t":"사울이 모든 백성을 군사로 불러 모으고 그일라로 내려가서 다윗과 그의 사람들을 에워싸려 하더니"},{"n":9,"t":"다윗이 사울의 자기를 해하려 하는 계교를 알고 제사장 아비아달에게 이르되 에봇을 이리로 가져오라 하고"},{"n":10,"t":"다윗이 가로되 이스라엘 하나님 여호와여 사울이 나의 연고로 이성을 멸하려고 그일라로 내려오기를 꾀한다 함을 주의 종이 분명히 들었나이다"},{"n":11,"t":"그일라 사람들이 나를 그의 손에 붙이겠나이까 주의 종의 들은 대로 사울이 내려 오겠나이까 이스라엘의 하나님 여호와여 원컨대 주의 종에게 일러 주옵소서 여호와께서 가라사대 그가 내려 오리라"},{"n":12,"t":"다윗이 가로되 그일라 사람들이 나와 내 사람들을 사울의 손에 붙이겠나이까 여호와께서 가라사대 그들이 너를 붙이리라"},{"n":13,"t":"다윗과 그의 사람 육백 명 가량이 일어나 그일라를 떠나서 갈 수 있는 곳으로 갔더니 다윗이 그일라에서 피한 것을 혹이 사울에게 고하매 사울이 가기를 그치니라"},{"n":14,"t":"다윗이 황무지 요새에도 있었고 또 십 황무지 산골에도 유하였으므로 사울이 매일 찾되 하나님이 그를 그의 손에 붙이지 아니하시니라"},{"n":15,"t":"다윗이 사울의 자기 생명을 찾으려고 나온 것을 보았으므로 그가 십 황무지 수풀에 있었더니"},{"n":16,"t":"사울의 아들 요나단이 일어나 수풀에 들어가서 다윗에게 이르러 그로 하나님을 힘있게 의지하게 하였는데"},{"n":17,"t":"곧 요나단이 그에게 이르기를 두려워 말라 내 부친 사울의 손이 네게 미치지 못할 것이요 너는 이스라엘 왕이 되고 나는 네 다음이 될 것을 내 부친 사울도 안다 하니라"},{"n":18,"t":"두 사람이 여호와 앞에서 언약하고 다윗은 수풀에 거하고 요나단은 자기 집으로 돌아가니라"},{"n":19,"t":"때에 십 사람들이 기브아에 이르러 사울에게 나아와 가로되 다윗이 우리와 함께 광야 남편 하길라 산 수풀 요새에 숨지 아니하였나이까"},{"n":20,"t":"그러하온즉 왕은 내려오시기를 원하시는 대로 내려 오소서 그를 왕의 손에 붙일 것이 우리의 의무니이다"},{"n":21,"t":"사울이 가로되 너희가 나를 긍휼히 여겼으니 여호와께 복받기를 원하노라"},{"n":22,"t":"혹이 내게 말하기를 그가 심히 공교히 행동한다 하나니 너희는 가서 더 자세히 살펴서 그가 어디 은적하였으며 누가 거기서 그를 보았는지 알아보고"},{"n":23,"t":"그가 숨어 있는 모든 곳을 탐지하고 실상을 내게 회보하라 내가 너희와 함께 가리니 그가 이 땅에 있으면 유다 천천인 중에서 그를 찾아내리라"},{"n":24,"t":"그들이 일어나 사울보다 먼저 십으로 가니라 다윗과 그의 사람들이 광야 남편 마온 황무지 아라바에 있더니"},{"n":25,"t":"사울과 그의 사람들이 찾으러 온 것을 혹이 다윗에게 고하매 이에 다윗이 바위로 내려 마온 황무지에 있더니 사울이 듣고 마온 황무지로 다윗을 따라가서는"},{"n":26,"t":"사울이 산 이편으로 가매 다윗과 그의 사람들은 산 저편으로 가며 다윗이 사울을 두려워하여 급히 피하려 하였으니 이는 사울과 그의 사람들이 다윗과 그의 사람들을 에워싸고 잡으려 함이었더라"},{"n":27,"t":"사자가 사울에게 와서 가로되 급히 오소서 블레셋 사람이 땅을 침노하나이다"},{"n":28,"t":"이에 사울이 다윗 쫓기를 그치고 돌아와서 블레셋 사람을 치러 갔으므로 그곳을 셀라하마느곳이라 칭하니라"},{"n":29,"t":"다윗이 거기서 올라가서 엔게디 요새에 거하니라"}],"kids":[]}},{"chapter":24,"title":"엔게디에서 사울을 살려줌","verses":{"krv":[{"n":1,"t":"사울이 블레셋 사람을 따르다가 돌아오매 혹이 그에게 고하여 가로되 보소서 다윗이 엔게디 황무지에 있더이다"},{"n":2,"t":"사울이 온 이스라엘에서 택한 사람 삼천을 거느리고 다윗과 그의 사람들을 찾으러 들염소 바위로 갈새"},{"n":3,"t":"길 가 양의 우리에 이른즉 굴이 있는지라 사울이 그 발을 가리우러 들어가니라 다윗과 그의 사람들이 그 굴 깊은 곳에 있더니"},{"n":4,"t":"다윗의 사람들이 가로되 보소서 여호와께서 당신에게 이르시기를 내가 원수를 네 손에 붙이리니 네 소견에 선한 대로 그에게 행하라 하시더니 이것이 그 날이니이다 다윗이 일어나서 사울의 겉옷자락을 가만히 베니라"},{"n":5,"t":"그리한 후에 사울의 옷자락 벰을 인하여 다윗의 마음이 찔려"},{"n":6,"t":"자기 사람들에게 이르되 내가 손을 들어 여호와의 기름 부음을 받은 내 주를 치는 것은 여호와의 금하시는 것이니 그는 여호와의 기름 부음을 받은 자가 됨이니라 하고"},{"n":7,"t":"다윗이 이 말로 자기 사람들을 금하여 사울을 해하지 못하게 하니라 사울이 일어나 굴에서 나가 자기 길을 가니라"},{"n":8,"t":"그 후에 다윗도 일어나 굴에서 나가 사울의 뒤에서 외쳐 가로되 내 주 왕이여 하매 사울이 돌아보는지라 다윗이 땅에 엎드려 절하고"},{"n":9,"t":"사울에게 이르되 다윗이 왕을 해하려 한다고 하는 사람들의 말을 왕은 어찌하여 들으시나이까"},{"n":10,"t":"오늘 여호와께서 굴에서 왕을 내 손에 붙이신 것을 왕이 아셨을 것이니이다 혹이 나를 권하여 왕을 죽이라 하였으나 내가 왕을 아껴 말하기를 나는 내 손을 들어 내 주를 해치 아니하리니 그는 여호와의 기름 부음을 받은 자가 됨이니라 하였나이다"},{"n":11,"t":"나의 아버지여 보소서 내 손에 있는 왕의 옷자락을 보소서 내가 왕을 죽이지 아니하고 겉옷자락만 베었은즉 나의 손에 악이나 죄과가 없는 줄을 아실지니이다 왕은 내 생명을 찾아 해하려 하시나 나는 왕에게 범죄한 일이 없나이다"},{"n":12,"t":"여호와께서는 나와 왕 사이를 판단하사 나를 위하여 왕에게 보복하시려니와 내 손으로는 왕을 해하지 않겠나이다"},{"n":13,"t":"옛 속담에 말하기를 악은 악인에게서 난다 하였으니 내 손이 왕을 해하지 아니하리이다"},{"n":14,"t":"이스라엘 왕이 누구를 따라 나왔으며 누구를 쫓나이까 죽은 개나 벼룩을 쫓음이니이다"},{"n":15,"t":"그런즉 여호와께서 재판장이 되어 나와 왕 사이에 판결하사 나의 사정을 살펴 신원하시고 나를 왕의 손에서 건지시기를 원하나이다"},{"n":16,"t":"다윗이 사울에게 이같이 말하기를 마치매 사울이 가로되 내 아들 다윗아 이것이 네 목소리냐 하고 소리를 높여 울며"},{"n":17,"t":"다윗에게 이르되 나는 너를 학대하되 너는 나를 선대하니 너는 나보다 의롭도다"},{"n":18,"t":"네가 나 선대한 것을 오늘 나타내었나니 여호와께서 나를 네 손에 붙이셨으나 네가 나를 죽이지 아니하였도다"},{"n":19,"t":"사람이 그 원수를 만나면 그를 평안히 가게 하겠느냐 네가 오늘날 내게 행한 일을 인하여 여호와께서 네게 선으로 갚으시기를 원하노라"},{"n":20,"t":"보라 나는 네가 반드시 왕이 될 것을 알고 이스라엘 나라가 네 손에 견고히 설 것을 아노니"},{"n":21,"t":"그런즉 너는 내 후손을 끊지 아니하며 내 아비의 집에서 내 이름을 멸하지 아니할 것을 이제 여호와로 내게 맹세하라"},{"n":22,"t":"다윗이 사울에게 맹세하매 사울은 집으로 돌아가고 다윗과 그의 사람들은 요새로 올라가니라"}],"kids":[]}},{"chapter":25,"title":"사무엘의 죽음과 아비가일","verses":{"krv":[{"n":1,"t":"사무엘이 죽으매 온 이스라엘 무리가 모여 그를 애곡하며 라마 그의 집에서 그를 장사한지라 다윗이 일어나 바란 광야로 내려가니라"},{"n":2,"t":"마온에 한 사람이 있는데 그 업이 갈멜에 있고 심히 부하여 양이 삼천이요 염소가 일천이므로 그가 갈멜에서 그 양털을 깎고 있었으니"},{"n":3,"t":"그 사람의 이름은 나발이요 그 아내의 이름은 아비가일이라 그 여자는 총명하고 용모가 아름다우나 남자는 완고하고 행사가 악하며 그는 갈멜 족속이었더라"},{"n":4,"t":"다윗이 광야에 있어서 나발이 자기 양털을 깎는다 함을 들은지라"},{"n":5,"t":"다윗이 이에 열 소년을 보내며 그 소년들에게 이르되 너희는 갈멜로 올라가 나발에게 이르러 내 이름으로 그에게 문안하고"},{"n":6,"t":"이같이 그 부하게 사는 자에게 이르기를 너는 평강하라 네 집도 평강하라 네 소유의 모든 것도 평강하라"},{"n":7,"t":"네게 앙털 깎는 자들이 있다 함을 이제 내가 들었노라 네 목자들이 우리와 함께 있었으나 우리가 그들을 상치 아니하였고 그들이 갈멜에 있는 동안에 그들의 것을 하나도 잃지 아니하였나니"},{"n":8,"t":"네 소년들에게 물으면 그들이 네게 고하리라 그런즉 내 소년들로 네게 은혜를 얻게 하라 우리가 좋은 날에 왔은즉 네 손에 있는 대로 네 종들과 네 아들 다윗에게 주기를 원하노라 하더라 하라"},{"n":9,"t":"다윗의 소년들이 가서 다윗의 이름으로 이 모든 말을 나발에게 고하기를 마치매"},{"n":10,"t":"나발이 다윗의 사환들에게 대답하여 가로되 다윗은 누구며 이새의 아들은 누구뇨 근일에 각기 주인에게서 억지로 떠나는 종이 많도다"},{"n":11,"t":"내가 어찌 내 떡과 물과 내 양털 깎는 자를 위하여 잡은 고기를 가져 어디로서인지 알지도 못하는 자들에게 주겠느냐 한지라"},{"n":12,"t":"이에 다윗의 소년들이 돌이켜 자기 길로 행하여 돌아와서 이 모든 말로 그에게 고하매"},{"n":13,"t":"다윗이 자기 사람들에게 이르되 너희는 각기 칼을 차라 각기 칼을 차매 다윗도 자기 칼을 차고 사백 명 가량은 데리고 올라가고 이백 명은 소유물 곁에 있게 하니라"},{"n":14,"t":"소년 중 하나가 나발의 아내 아비가일에게 고하여 가로되 다윗이 우리 주인에게 문안하러 광야에서 사자들을 보내었거늘 주인이 그들을 수욕하였나이다"},{"n":15,"t":"우리가 들에 있어 그들과 상종할 동안에 그 사람들이 우리를 매우 선대하였으므로 우리가 상하거나 잃은 것이 없었으니"},{"n":16,"t":"우리가 양을 지키는 동안에 그들이 우리와 함께 있어 밤낮 우리에게 담이 되었음이라"},{"n":17,"t":"그런즉 이제 당신은 어떻게 할 것을 알아 생각하실지니 이는 다윗이 우리 주인과 주인의 온 집을 해하기로 결정하였음이니이다 주인은 불량한 사람이라 더불어 말할 수 없나이다"},{"n":18,"t":"아비가일이 급히 떡 이백 덩이와 포도주 두 가죽 부대와 잡아 준비한 양 다섯과 볶은 곡식 다섯 세아와 건포도 백 송이와 무화과 뭉치 이백을 취하여 나귀들에게 싣고"},{"n":19,"t":"소년들에게 이르되 내 앞서 가라 나는 너희 뒤에 가리라 하고 그 남편 나발에게는 고하지 아니하니라"},{"n":20,"t":"아비가일이 나귀를 타고 산 유벽한 곳으로 좇아 내려가더니 다윗과 그의 사람들이 자기에게로 마주 내려오는 것을 만나니라"},{"n":21,"t":"다윗이 이미 말하기를 내가 이 자의 소유물을 광야에서 지켜 그 모든 것을 하나도 손실이 없게 한 것이 진실로 허사라 그가 악으로 나의 선을 갚는도다"},{"n":22,"t":"내가 그에게 속한 모든 것 중 한 남자라도 아침까지 남겨두면 하나님은 다윗에게 벌을 내리시고 또 내리시기를 원하노라 하였더라"},{"n":23,"t":"아비가일이 다윗을 보고 급히 나귀에서 내려 다윗의 앞에 엎드려 그 얼굴을 땅에 대니라"},{"n":24,"t":"그가 다윗의 발에 엎드려 가로되 내 주여 청컨대 이 죄악을 나 곧 내게로 돌리시고 여종으로 주의 귀에 말하게 하시고 이 여종의 말을 들으소서"},{"n":25,"t":"원하옵나니 내 주는 이 불량한 사람 나발을 개의치 마옵소서 그 이름이 그에게 적당하니 그 이름이 나발이라 그는 미련한 자니이다 여종은 내 주의 보내신 소년들을 보지 못하였나이다"},{"n":26,"t":"내 주여 여호와께서 사시고 내 주도 살아계시거니와 내 주의 손으로 피를 흘려 친히 보수하시는 일을 여호와께서 막으셨으니 내 주의 원수들과 내 주를 해하려 하는 자들은 나발과 같이 되기를 원하나이다"},{"n":27,"t":"여종이 내 주에게 가져온 이 예물로 내 주를 좇는 이 소년들에게 주게 하시고"},{"n":28,"t":"주의 여종의 허물을 사하여 주옵소서 여호와께서 반드시 내 주를 위하여 든든한 집을 세우시리니 이는 내 주께서 여호와의 싸움을 싸우심이요 내 주의 일생에 내 주에게서 악한 일을 찾을 수 없음이니이다"},{"n":29,"t":"사람이 일어나서 내 주를 쫓아 내 주의 생명을 찾을지라도 내 주의 생명은 내 주의 하나님 여호와와 함께 생명싸개 속에 싸였을 것이요 내 주의 원수들의 생명은 물매로 던지듯 여호와께서 그것을 던지시리이다"},{"n":30,"t":"여호와께서 내 주에 대하여 하신 말씀대로 모든 선을 내 주에게 행하사 내 주를 이스라엘의 지도자로 세우신 때에"},{"n":31,"t":"내 주께서 무죄한 피를 흘리셨다든지 내 주께서 친히 보수하셨다든지 함을 인하여 슬퍼하실 것도 없고 내 주의 마음에 걸리는 것도 없으시리니 다만 여호와께서 내 주를 후대하신 때에 원컨대 내 주의 여종을 생각하소서"},{"n":32,"t":"다윗이 아비가일에게 이르되 오늘날 너를 보내어 나를 영접케 하신 이스라엘의 하나님 여호와를 찬송할지로다"},{"n":33,"t":"또 네 지혜를 칭찬할지며 또 네게 복이 있을지로다 오늘날 내가 피를 흘릴 것과 친히 보수하는 것을 네가 막았느니라"},{"n":34,"t":"나를 막아 너를 해하지 않게 하신 이스라엘의 하나님 여호와의 사심으로 맹세하노니 네가 급히 와서 나를 영접지 아니하였더면 밝는 아침에는 과연 나발에게 한 남자도 남겨두지 아니하였으리라"},{"n":35,"t":"다윗이 그가 가져온 것을 그의 손에서 받고 그에게 이르되 네 집으로 평안히 올라가라 내가 네 말을 듣고 네 청을 허락하노라"},{"n":36,"t":"아비가일이 나발에게로 돌아오니 그가 왕의 잔치 같은 잔치를 그 집에 배설하고 대취하여 마음에 기뻐하므로 아비가일이 밝는 아침까지는 다소간 말하지 아니하다가"},{"n":37,"t":"아침에 나발이 포도주가 깬 후에 그 아내가 그에게 이 일을 고하매 그가 낙담하여 몸이 돌과 같이 되었더니"},{"n":38,"t":"한 열흘 후에 여호와께서 나발을 치시매 그가 죽으니라"},{"n":39,"t":"다윗이 나발의 죽었다 함을 듣고 가로되 나발에게 당한 나의 욕을 신설하사 종으로 악한 일을 하지 않게 하신 여호와를 찬송할지로다 여호와께서 나발의 악행을 그 머리에 돌리셨도다 하니라 다윗이 아비가일로 자기 아내를 삼으려고 보내어 그에게 말하게 하매"},{"n":40,"t":"다윗의 사환들이 갈멜에 가서 아비가일에게 이르러 그에게 일러 가로되 다윗이 당신을 아내로 삼고자 하여 우리를 당신께 보내더이다"},{"n":41,"t":"그가 일어나 몸을 굽혀 얼굴을 땅에 대고 가로되 내 주의 여종은 내 주의 사환들의 발 씻길 종이니이다 하고"},{"n":42,"t":"급히 일어나서 나귀를 타고 따르는 처녀 다섯과 함께 다윗의 사자들을 따라가서 다윗의 아내가 되니라"},{"n":43,"t":"다윗이 또 이스르엘 아히노암을 취하였더니 그들 두 사람이 자기 아내가 되니라"},{"n":44,"t":"사울이 그 딸 다윗의 아내 미갈을 갈림에 사는 라이스의 아들 발디에게 주었더라"}],"kids":[]}},{"chapter":26,"title":"다윗이 또 사울을 살려줌","verses":{"krv":[{"n":1,"t":"십 사람이 기브아에 와서 사울에게 이르러 가로되 다윗이 광야 앞 하길라 산에 숨지 아니하였나이까"},{"n":2,"t":"사울이 일어나 십 황무지에서 다윗을 찾으려고 이스라엘에서 택한 사람 삼천과 함께 십 황무지로 내려가서"},{"n":3,"t":"광야 앞 하길라 산 길 가에 진치니라 다윗이 황무지에 있더니 사울이 자기를 따라 황무지로 들어옴을 깨닫고"},{"n":4,"t":"이에 탐정을 보내어 사울이 과연 이른줄 알고"},{"n":5,"t":"일어나 사울의 진 친 곳에 이르러 사울과 넬의 아들 군대장관 아브넬의 유하는 곳을 본즉 사울이 진 가운데 누웠고 백성은 그를 둘러 진 쳤더라"},{"n":6,"t":"이에 다윗이 헷 사람 아히멜렉과 스루야의 아들 요압의 아우 아비새에게 물어 가로되 누가 나로 더불어 진에 내려가서 사울에게 이르겠느냐 아비새가 가로되 내가 함께 가겠나이다"},{"n":7,"t":"다윗과 아비새가 밤에 그 백성에게 나아가 본즉 사울이 진 가운데 누워 자고 창은 머리 곁 땅에 꽂혔고 아브넬과 백성들은 그를 둘러 누웠는지라"},{"n":8,"t":"아비새가 다윗에게 이르되 하나님이 오늘날 당신의 원수를 당신의 손에 붙이셨나이다 그러므로 청하오니 나로 창으로 그를 찔러서 단 번에 땅에 꽂게 하소서 내가 그를 두 번 찌를 것이 없으리이다"},{"n":9,"t":"다윗이 아비새에게 이르되 죽이지 말라 누구든지 손을 들어 여호와의 기름 부음을 받은 자를 치면 죄가 없겠느냐"},{"n":10,"t":"또 가로되 여호와께서 사시거니와 여호와께서 그를 치시리니 혹 죽을 날이 이르거나 혹 전장에 들어가서 망하리라"},{"n":11,"t":"내가 손을 들어 여호와의 기름 부음을 받은 자를 치는 것을 여호와께서 금하시나니 너는 그의 머리 곁에 있는 창과 물병만 가지고 가자 하고"},{"n":12,"t":"다윗이 사울의 머리 곁에서 창과 물병을 가지고 떠나가되 깨든지 이를 보든지 알든지 하는 사람이 없었으니 이는 여호와께서 그들로 깊이 잠들게 하셨으므로 그들이 다 잠이었더라"},{"n":13,"t":"이에 다윗이 건너편으로 가서 멀리 산꼭대기에 서니 상거가 멀더라"},{"n":14,"t":"다윗이 백성과 넬의 아들 아브넬을 대하여 외쳐 가로되 아브넬아 너는 대답지 아니하느냐 아브넬이 대답하여 가로되 왕을 부르는 너는 누구냐"},{"n":15,"t":"다윗이 아브넬에게 이르되 네가 용사가 아니냐 이스라엘 중에 너 같은 자가 누구냐 그러한데 네가 어찌하여 네 주 왕을 보호하지 아니하느냐 백성 중 한 사람이 네 주 왕을 죽이려고 들어갔었느니라"},{"n":16,"t":"네 행한 이 일이 선치 못하도다 여호와께서 사시거니와 여호와의 기름 부음 받은 너희 주를 보호하지 아니하였으니 너희는 마땅히 죽을 자니라 이제 왕의 창과 왕의 머리 곁에 있던 물병이 어디 있나 보라"},{"n":17,"t":"사울이 다윗의 음성을 알아 듣고 가로되 내 아들 다윗아 이것이 네 음성이냐 다윗이 가로되 내 주 왕이여 내 음성이니이다"},{"n":18,"t":"또 가로되 내 주는 어찌하여 주의 종을 쫓으시나이까 내가 무엇을 하였으며 내 손에 무슨 악이 있나이까"},{"n":19,"t":"청컨대 내 주 왕은 이제 종의 말을 들으소서 만일 왕을 격동시켜 나를 해하려 하는 이가 여호와시면 여호와께서는 제물을 받으시기를 원하나이다마는 만일 인자들이면 그들이 여호와 앞에 저주를 받으리니 이는 그들이 이르기를 너는 가서 다른 신들을 섬기라 하고 오늘날 나를 쫓아내어 여호와의 기업에 붙지 못하게 함이니이다"},{"n":20,"t":"그런즉 청컨대 여호와 앞에서 먼 이곳에서 이제 나의 피로 땅에 흐르지 말게 하옵소서 이는 산에서 메추라기를 사냥하는 자와 같이 이스라엘 왕이 한 벼룩을 수색하러 나오셨음이니이다"},{"n":21,"t":"사울이 가로되 내가 범죄하였도다 내 아들 다윗아 돌아오라 네가 오늘 내 생명을 귀중히 여겼은즉 내가 다시는 너를 해하려 하지 아니하리라 내가 어리석은 일을 하였으니 대단히 잘못 되었도다"},{"n":22,"t":"다윗이 대답하여 가로되 왕은 창을 보소서 한 소년을 보내어 가져가게 하소서"},{"n":23,"t":"여호와께서 각 사람에게 그 의와 신실을 갚으시리니 이는 여호와께서 오늘날 왕을 내 손에 붙이셨으되 나는 손을 들어 여호와의 기름 부음을 받은 자 치기를 원치 아니하였음이니이다"},{"n":24,"t":"오늘날 왕의 생명을 내가 중히 여긴 것 같이 내 생명을 여호와께서 중히 여기셔서 모든 환난에서 나를 구하여 내시기를 바라나이다"},{"n":25,"t":"사울이 다윗에게 이르되 내 아들 다윗아 네게 복이 있을지로다 네가 큰 일을 행하겠고 반드시 승리를 얻으리라 하니라 다윗은 자기 길로 가고 사울은 자기 곳으로 돌아가니라"}],"kids":[]}},{"chapter":27,"title":"다윗이 블레셋으로 피함","verses":{"krv":[{"n":1,"t":"다윗이 그 마음에 생각하기를 내가 후일에는 사울의 손에 망하리니 블레셋 사람의 땅으로 피하여 들어가는 것이 상책이로다 사울이 이스라엘 온 경내에서 나를 수색하다가 절망하리니 내가 그 손에서 벗어나리라 하고"},{"n":2,"t":"일어나 함께 있는 육백 인으로 더불어 가드 왕 마옥의 아들 아기스에게로 건너가니라"},{"n":3,"t":"다윗과 그의 사람들이 각기 가족을 거느리고 가드에서 아기스와 동거하였는데 다윗이 그 두 아내 이스르엘 여자 아히노암과 나발의 아내 되었던 갈멜 여자 아비가일과 함께 하였더니"},{"n":4,"t":"다윗이 가드에 도망한 것을 혹이 사울에게 고하매 사울이 다시는 그를 수색하지 아니하니라"},{"n":5,"t":"다윗이 아기스에게 이르되 내가 당신께 은혜를 받았거든 지방 성읍 중 한 곳을 주어 나로 거하게 하소서 당신의 종이 어찌 당신과 함께 왕도에 거하리이까"},{"n":6,"t":"아기스가 그 날에 시글락을 그에게 주었으므로 시글락이 오늘까지 유다 왕에게 속하니라"},{"n":7,"t":"다윗이 블레셋 사람의 지방에 거한 날 수는 일년 넉달이었더라"},{"n":8,"t":"다윗과 그의 사람들이 올라가서 그술 사람과 기르스 사람과 아말렉 사람을 침노하였으니 그들은 옛적부터 술과 애굽 땅으로 지나가는 지방의 거민이라"},{"n":9,"t":"다윗이 그 땅을 쳐서 남녀를 살려 두지 아니하고 양과 소와 나귀와 약대와 의복을 취하고 돌아와서 아기스에게 이르매"},{"n":10,"t":"아기스가 가로되 너희가 오늘은 누구를 침노하였느냐 다윗이 가로되 유다 남방과 여라무엘 사람의 남방과 겐 사람의 남방이니이다"},{"n":11,"t":"다윗이 그 남녀를 살려 가드로 데려가지 아니한 것은 그의 생각에 그들이 우리에게 대하여 이르기를 다윗의 행사가 이러하여 블레셋 사람의 지방에 거하는 동안에 이같이 행하는 습관이 있다 할까 두려워함이었더라"},{"n":12,"t":"아기스가 다윗을 믿고 말하기를 다윗이 자기 백성 이스라엘에게 심히 미움을 받게 하였으니 그는 영영히 내 사역자가 되리라 하니라"}],"kids":[]}},{"chapter":28,"title":"사울과 엔돌의 신접한 여인","verses":{"krv":[{"n":1,"t":"그 때에 블레셋 사람이 이스라엘을 쳐서 싸우려고 군대를 모집한지라 아기스가 다윗에게 이르되 너는 밝히 알라 너와 네 사람들이 나와 한가지로 나가서 군대에 참가할 것이니라"},{"n":2,"t":"다윗이 아기스에게 이르되 그러면 당신이 종의 행할 바를 아시리이다 아기스가 다윗에게 이르되 그러면 내가 너로 영영히 내 머리 지키는 자를 삼으리라 하니라"},{"n":3,"t":"사무엘이 죽었으므로 온 이스라엘이 그를 애곡하며 그의 본성 라마에 장사하였고 사울은 신접한 자와 박수를 그 땅에서 쫓아 내었었더라"},{"n":4,"t":"블레셋 사람이 모여 수넴에 이르러 진 치매 사울이 온 이스라엘을 모아 길보아에 진 쳤더니"},{"n":5,"t":"사울이 블레셋 사람의 군대를 보고 두려워서 그 마음이 크게 떨린지라"},{"n":6,"t":"사울이 여호와께 묻자오되 여호와께서 꿈으로도, 우림으로도, 선지자로도 그에게 대답지 아니하시므로"},{"n":7,"t":"사울이 그 신하들에게 이르되 나를 위하여 신접한 여인을 찾으라 내가 그리로 가서 그에게 물으리라 그 신하들이 그에게 이르되 보소서 엔돌에 신접한 여인이 있나이다"},{"n":8,"t":"사울이 다른 옷을 입어 변장하고 두 사람과 함께 갈새 그들이 밤에 그 여인에게 이르러는 사울이 가로되 청하노니 나를 위하여 신접한 술법으로 내가 네게 말하는 사람을 불러올리라"},{"n":9,"t":"여인이 그에게 이르되 네가 사울의 행한 일 곧 그가 신접한 자와 박수를 이 땅에서 멸절시켰음을 아나니 네가 어찌하여 내 생명에 올무를 놓아 나를 죽게 하려느냐"},{"n":10,"t":"사울이 여호와로 그에게 맹세하여 가로되 여호와께서 사시거니와 네가 이 일로는 벌을 당치 아니하리라"},{"n":11,"t":"여인이 가로되 내가 누구를 네게로 불러 올리랴 사울이 가로되 사무엘을 불러 올리라"},{"n":12,"t":"여인이 사무엘을 보고 큰 소리로 외치며 사울에게 말하여 가로되 당신이 어찌하여 나를 속이셨나이까 당신이 사울이시니이다"},{"n":13,"t":"왕이 그에게 이르되 두려워 말라 네가 무엇을 보았느냐 여인이 사울에게 이르되 내가 신이 땅에서 올라오는 것을 보았나이다"},{"n":14,"t":"사울이 그에게 이르되 그 모양이 어떠하냐 그가 가로되 한 노인이 올라 오는데 그가 겉옷을 입었나이다 사울이 그가 사무엘인줄 알고 그 얼굴을 땅에 대고 절하니라"},{"n":15,"t":"사무엘이 사울에게 이르되 네가 어찌하여 나를 불러 올려서 나로 분요케 하느냐 사울이 대답하되 나는 심히 군급하니이다 블레셋 사람은 나를 향하여 군대를 일으켰고 하나님은 나를 떠나서 다시는 선지자로도, 꿈으로도 내게 대답지 아니하시기로 나의 행할 일을 배우려고 당신을 불러 올렸나이다"},{"n":16,"t":"사무엘이 가로되 여호와께서 너를 떠나 네 대적이 되셨거늘 네가 어찌하여 내게 묻느냐"},{"n":17,"t":"여호와께서 나로 말씀하신 대로 네게 행하사 나라를 네 손에서 떼어 네 이웃 다윗에게 주셨느니라"},{"n":18,"t":"네가 여호와의 목소리를 순종치 아니하고 그의 진노를 아말렉에게 쏟지 아니하였으므로 여호와께서 오늘날 이 일을 네게 행하셨고"},{"n":19,"t":"여호와께서 이스라엘을 너와 함께 블레셋 사람의 손에 붙이시리니 내일 너와 네 아들들이 나와 함께 있으리라 여호와께서 또 이스라엘 군대를 블레셋 사람의 손에 붙이시리라"},{"n":20,"t":"사울이 갑자기 땅에 온전히 엎드러지니 이는 사무엘의 말을 인하여 심히 두려워함이요 또 그 기력이 진하였으니 이는 그가 종일 종야에 식물을 먹지 못하였음이라"},{"n":21,"t":"그 여인이 사울에게 이르러 그 심히 고통함을 보고 그에게 이르되 여종이 왕의 말씀을 듣고 나의 생명을 아끼지 아니하고 왕이 내게 이르신 말씀을 청종하였사오니"},{"n":22,"t":"그런즉 청컨대 이제 여종의 말을 들으사 나로 왕의 앞에 한 조각 떡을 드리게 하시고 왕은 잡수시고 길 가실 때에 기력을 얻으소서"},{"n":23,"t":"사울이 거절하여 가로되 내가 먹지 아니하겠노라 그 신하들과 여인이 강권하매 그 말을 듣고 땅에서 일어나 침상에 앉으니라"},{"n":24,"t":"여인의 집에 살진 송아지가 있으므로 그것을 급히 잡고 가루를 취하여 뭉쳐 무교병을 만들고 구워서"},{"n":25,"t":"사울의 앞에와 그 신하들의 앞에 드리니 그들이 먹고 일어나서 그 밤에 가니라"}],"kids":[]}},{"chapter":29,"title":"블레셋이 다윗을 돌려보냄","verses":{"krv":[{"n":1,"t":"블레셋 사람들은 그 모든 군대를 아벡에 모았고 이스라엘 사람들은 이스르엘에 있는 샘 곁에 진 쳤더라"},{"n":2,"t":"블레셋 사람의 장관들은 수백씩 수천씩 영솔하여 나아가고 다윗과 그의 사람들은 아기스와 함께 그 뒤에서 나아가더니"},{"n":3,"t":"블레셋 사람의 방백들이 가로되 이 히브리 사람들이 무엇을 하려느냐 아기스가 블레셋 사람의 방백들에게 이르되 이는 이스라엘 왕 사울의 신하 다윗이 아니냐 그가 나와 함께 있은지 여러 날 여러 해로되 그가 망명하여 온 날부터 오늘까지 내가 그의 허물을 보지 못하였노라"},{"n":4,"t":"블레셋 사람의 방백들이 그에게 노한지라 블레셋 방백들이 그에게 이르되 이 사람을 돌려 보내어 왕이 그에게 정하신 그 처소로 가게 하소서 그는 우리와 함께 싸움에 내려가지 못하리니 그가 전장에서 우리의 대적이 될까 하나이다 그가 무엇으로 그 주와 다시 화합하리이까 이사람들의 머리로 하지 아니하겠나이까"},{"n":5,"t":"그들이 춤추며 창화하여 가로되 사울의 죽인 자는 천천이요 다윗은 만만이로다 하던 이 다윗이 아니니이까"},{"n":6,"t":"아기스가 다윗을 불러 그에게 이르되 여호와께서 사시거니와 네가 정직하여 내게 온 날부터 오늘까지 네게 악이 있음을 보지 못하였으니 나와 함께 군중에 출입하는 것이 나의 소견에는 좋으나 장관들이 너를 좋아하지 아니하니"},{"n":7,"t":"너는 돌이켜 평안히 가서 블레셋 사람의 장관들에게 거슬려 보이게 말라"},{"n":8,"t":"다윗이 아기스에게 이르되 내가 무엇을 하였나이까 내가 당신의 앞에 오늘까지 있는 동안에 당신이 종에게서 무엇을 보셨기에 나로 가서 내 주 왕의 원수와 싸우지 못하게 하시나이까"},{"n":9,"t":"아기스가 다윗에게 대답하여 가로되 네가 내 목전에 하나님의 사자 같이 선한 것을 내가 아나 블레셋 사람의 방백들은 말하기를 그가 우리와 함께 전장에 올라가지 못하리라 하니"},{"n":10,"t":"그런즉 너는 너와 함께 온 네 주의 신하들로 더불어 새벽에 일어나라 너희는 새벽에 일어나서 밝거든 곧 떠나라"},{"n":11,"t":"이에 다윗이 자기 사람들로 더불어 일찍이 아침에 일어나서 떠나 블레셋 사람의 땅으로 돌아가고 블레셋 사람은 이스르엘로 올라 가니라"}],"kids":[]}},{"chapter":30,"title":"시글락을 약탈한 아말렉 추격","verses":{"krv":[{"n":1,"t":"다윗과 그의 사람들이 제삼일에 시글락에 이를 때에 아말렉 사람들이 이미 남방과 시글락을 침노하였는데 그들이 시글락을 쳐서 불사르고"},{"n":2,"t":"거기 있는 대소 여인들을 하나도 죽이지 아니하고 다 사로잡아 끌고 자기 길을 갔더라"},{"n":3,"t":"다윗과 그의 사람들이 성에 이르러 본즉 성이 불탔고 자기들의 아내와 자녀들이 사로잡혔는지라"},{"n":4,"t":"다윗과 그와 함께 한 백성이 울 기력이 없도록 소리를 높여 울었더라"},{"n":5,"t":"(다윗의 두 아내 이스르엘 여인 아히노암과 갈멜 사람 나발의 아내 되었던 아비가일도 사로잡혔더라)"},{"n":6,"t":"백성이 각기 자녀들을 위하여 마음이 슬퍼서 다윗을 돌로 치자 하니 다윗이 크게 군급하였으나 그 하나님 여호와를 힘입고 용기를 얻었더라"},{"n":7,"t":"다윗이 아히멜렉의 아들 제사장 아비아달에게 이르되 청컨대 에봇을 내게로 가져오라 아비아달이 에봇을 다윗에게로 가져오매"},{"n":8,"t":"다윗이 여호와께 묻자와 가로되 내가 이 군대를 쫓아가면 미치겠나이까 여호와께서 대답하시되 쫓아가라 네가 반드시 미치고 정녕 도로 찾으리라"},{"n":9,"t":"이에 다윗과 그와 함께 한 육백 명이 가서 브솔 시내에 이르러는 뒤 떨어진 자를 거기 머물렀으되"},{"n":10,"t":"곧 피곤하여 브솔 시내를 건너지 못하는 이백 인을 머물렀고 다윗은 사백 인을 거느리고 쫓아가니라"},{"n":11,"t":"무리가 들에서 애굽 사람 하나를 만나 다윗에게로 데려다가 떡을 주어 먹게 하며 물을 마시우고"},{"n":12,"t":"무화과 뭉치에서 뗀 덩이 하나와 건포도 두 송이를 주었으니 그가 낮 사흘, 밤 사흘을 떡도 먹지 못하였고 물도 마시지 못하였음이라 그가 먹고 정신을 차리매"},{"n":13,"t":"다윗이 그에게 이르되 너는 뉘게 속하였으며 어디로서냐 가로되 나는 애굽 소년이요 아말렉 사람의 종이더니 사흘 전에 병이 들매 주인이 나를 버렸나이다"},{"n":14,"t":"우리가 그렛 사람의 남방과 유다에 속한 지방과 갈멜 남방을 침노하고 시글락을 불살랐나이다"},{"n":15,"t":"다윗이 그에게 이르되 네가 나를 그 군대에게로 인도하겠느냐 그가 가로되 당신이 나를 죽이지도 아니하고 내 주인의 수중에 붙이지도 아니하겠다고 하나님으로 맹세하소서 그리하면 내가 당신을 이 군대에게로 인도하리이다"},{"n":16,"t":"그가 인도하여 내려가니 그들이 온 땅에 편만하여 블레셋 사람의 땅과 유다 땅에서 크게 탈취하였음을 인하여 먹고 마시며 춤추는지라"},{"n":17,"t":"다윗이 새벽부터 이튿날 저물때까지 그들을 치매 약대 타고 도망한 소년 사백 명 외에는 피한 사람이 없었더라"},{"n":18,"t":"다윗이 아말렉 사람의 취하였던 모든 것을 도로 찾고 그 두 아내를 구원하였고"},{"n":19,"t":"그들의 탈취하였던 것 곧 무리의 자녀들이나 빼앗겼던 것의 대소를 물론하고 아무 것도 잃은 것이 없이 다윗이 도로 찾아왔고"},{"n":20,"t":"또 양떼와 소떼를 다 탈취하였더니 무리가 그 가축 앞에 몰고 가며 가로되 이는 다윗의 탈취한 것이라 하였더라"},{"n":21,"t":"다윗이 이왕에 피곤하여 능히 자기를 따르지 못하므로 브솔 시내에 머물게 한 이백 인에게 오매 그들이 다윗과 그와 함께 한 백성을 영접하러 나온지라 다윗이 그 백성에게 이르러 문안하매"},{"n":22,"t":"다윗과 함께 갔던 자 중에 악한 자와 비류들이 다 가로되 그들이 우리와 함께 가지 아니하였은즉 우리가 도로 찾은 물건은 무엇이든지 그들에게 주지 말고 각 사람의 처자만 주어서 데리고 떠나가게 하라 하는지라"},{"n":23,"t":"다윗이 가로되 나의 형제들아 여호와께서 우리를 보호하시고 우리를 치러 온 그 군대를 우리 손에 붙이셨은즉 그가 우리에게 주신 것을 너희가 이같이 못하리라"},{"n":24,"t":"이 일에 누가 너희를 듣겠느냐 전장에 내려갔던 자의 분깃이나 소유물 곁에 머물렀던 자의 분깃이 일반일지니 같이 분배할 것이니라 하고"},{"n":25,"t":"그 날부터 다윗이 이것으로 이스라엘의 율례와 규례를 삼았더니 오늘까지 이르니라"},{"n":26,"t":"다윗이 시글락에 이르러 탈취물을 그 친구 유다 장로들에게 보내어 가로되 보라 여호와의 원수에게서 탈취한 것을 너희에게 선사하노라 하고"},{"n":27,"t":"벧엘에 있는 자와 남방 라못에 있는 자와 얏딜에 있는 자와"},{"n":28,"t":"아로엘에 있는 자와 십못에 있는 자와 에스드모아에 있는 자와"},{"n":29,"t":"라갈에 있는 자와 여라므엘 사람의 성읍들에 있는 자와 겐 사람의 성읍들에 있는 자와"},{"n":30,"t":"홀마에 있는 자와 고라산에 있는 자와 아닥에 있는 자와 헤브론에 있는 자에게와 다윗과 그의 사람들의 왕래하던 모든 곳에 보내었더라"},{"n":31,"t":"(없음)"}],"kids":[]}},{"chapter":31,"title":"길보아 산의 사울의 죽음","verses":{"krv":[{"n":1,"t":"블레셋 사람이 이스라엘을 치매 이스라엘 사람들이 블레셋 사람 앞에서 도망하여 길보아 산에서 엎드러져 죽으니라"},{"n":2,"t":"블레셋 사람들이 사울과 그 아들들을 쫓아 미쳐서 사울의 아들 요나단과 아비나답과 말기수아를 죽이니라"},{"n":3,"t":"사울이 패전하매 활 쏘는 자가 따라 미치니 사울이 그 활 쏘는 자를 인하여 중상한지라"},{"n":4,"t":"그가 병기 든 자에게 이르되 네 칼을 빼어 나를 찌르라 할례없는 자들이 와서 나를 찌르고 모욕할까 두려워하노라 하나 병기 든 자가 심히 두려워하여 즐겨 행치 아니하는지라 이에 사울이 자기 칼을 취하고 그 위에 엎드러지매"},{"n":5,"t":"병기 든 자가 사울의 죽음을 보고 자기도 자기 칼 위에 엎드러져 그와 함께 죽으니라"},{"n":6,"t":"사울과 그 세 아들과 병기 든 자와 그의 모든 사람이 다 그 날에 함께 죽었더라"},{"n":7,"t":"골짜기 저편에 있는 이스라엘 사람과 요단 건너편에 있는 자들이 이스라엘 사람들의 도망한 것과 사울과 그 아들들의 죽었음을 보고 성읍들을 버리고 도망하매 블레셋 사람들이 이르러 거기 거하니라"},{"n":8,"t":"그 이튿날 블레셋 사람들이 죽은 자를 벗기러 왔다가 사울과 그 세 아들이 길보아 산에서 죽은 것을 보고"},{"n":9,"t":"사울의 머리를 베고 그 갑옷을 벗기고 자기들의 신당과 백성에게 전파하기 위하여 그것을 블레셋 사람의 땅 사방에 보내고"},{"n":10,"t":"그 갑옷은 아스다롯의 집에 두고 그 시체는 벧산 성벽에 못 박으매"},{"n":11,"t":"길르앗 야베스 거민들이 블레셋 사람들의 사울에게 행한 일을 듣고"},{"n":12,"t":"모든 장사가 일어나 밤새도록 가서 사울과 그 아들들의 시체를 벧산 성벽에서 취하여 가지고 야베스에 돌아와서 거기서 불사르고"},{"n":13,"t":"그 뼈를 가져다가 야베스 에셀나무 아래 장사하고 칠 일을 금식하였더라"}],"kids":[]}}]}');

